import corporate_core as core

APP_TITLE = "BI Qualidade Corporativo"
BASE_DIR = Path(__file__).resolve().parent
MODULES_DIR = BASE_DIR / "modulos"
MANUAL_FILE = BASE_DIR / "manual" / "Manual_BI_Qualidade_Corporativo_RM_2026.pdf"

EMBEDDED_MODULES = {
    'indicadores_qualidade.py': '# app.py — INDICADORES QUALIDADE RS (WEB) — visão simplificada\n# Upgrade aplicado:\n# - Sem senha de abertura\n# - Mantém sempre o último upload salvo localmente\n# - Filtro inicial por Ano e Mês\n# - Modo de comparação entre dois períodos\n# - Comparação permite selecionar um ou mais meses no Período 1\n# - No comparativo, o Período 2 replica automaticamente os mesmos meses do Período 1\n# - Gráfico 1: número de ocorrências\n# - Gráfico 2: motivos das ocorrências\n# - Em comparação, ambos os gráficos usam barras com cores distintas por período/ano\n# - Exportação Excel inclui tabela, gráficos e dados de variação entre períodos\n# - Excel: eixo X dos gráficos em 45° e aba RECORTE compacta\n# - Abertura sempre em consulta normal, com todos os anos e meses da última base\n# - Filtro de mês ajustado para seleção direta, sem opção (Todos), reduzindo necessidade de duplo clique\n# - Versão dinâmica no formato RM_dd_mm_aaaa_HR, em itálico e fonte 10\n# - Botão de exportação descrito como Gerar relatório\n# - RECORTE com fonte/dimensões fixas e colunas auxiliares ocultas\n# - Gráficos nativos das abas DADOS com eixo X correto e rótulos sobre barras\n# - Recuperação automática reforçada da última base após inatividade\n# - Campo Manual integrado ao aplicativo, com download do PDF de funcionamento\n\nimport io\nimport json\nfrom datetime import datetime\nfrom pathlib import Path\n\nimport pandas as pd\nimport streamlit as st\nimport plotly.express as px\n\nfrom openpyxl import Workbook\nfrom openpyxl.utils.dataframe import dataframe_to_rows\nfrom openpyxl.utils import get_column_letter\nfrom openpyxl.styles import Font, Alignment, PatternFill, Border, Side\nfrom openpyxl.chart import BarChart\nfrom openpyxl.chart.reference import Reference\nfrom openpyxl.chart.label import DataLabelList\nfrom openpyxl.drawing.image import Image as XLImage\n\n# =========================================================\n# Configuração geral\n# =========================================================\nAPP_VERSION = datetime.now().strftime("RM_%d_%m_%Y_%HHR")\nAPP_NAME = "INDICADORES QUALIDADE RS"\nDEFAULT_SHEET = "Sheet1"\n\nLAST_DIR = Path("data/qualidade/.last_input")\nLAST_DIR.mkdir(exist_ok=True)\nLAST_FILE = LAST_DIR / "last_excel.bin"\nLAST_META = LAST_DIR / "last_excel_meta.json"\nAPP_STATE_FILE = LAST_DIR / "app_state_simplificado.json"\n\nCOL_CODIGO = "Código"\nCOL_TITULO = "Título"\nCOL_STATUS = "Status"\nCOL_DATA = "Data de emissão"\nCOL_MOTIVO = "Motivo Reclamação"\nCOL_RESP_OCORRENCIA = "Responsável"\nCOL_RESP_ANALISE = "Responsável da análise de causa"\nCOL_CATEGORIA = "Categoria"\nCOL_CLIENTE = "Cliente"\nCOL_SITUACAO = "Situação"\n\nDATE_FMT_BR = "%d/%m/%Y"\nMESES_ABREV = {\n    1: "Jan", 2: "Fev", 3: "Mar", 4: "Abr", 5: "Mai", 6: "Jun",\n    7: "Jul", 8: "Ago", 9: "Set", 10: "Out", 11: "Nov", 12: "Dez",\n}\nINV_MESES_ABREV = {v: k for k, v in MESES_ABREV.items()}\n\nCORES_COMPARACAO = ["#1F5C4B", "#8BBF24"]\nCOR_NORMAL = "#1F5C4B"\nCOR_ATRASO = "#B42318"\nCOR_FUNDO = "#F4F7F2"\nCOR_FUNDO_2 = "#EAF1EA"\nCOR_TEXTO = "#173D35"\nCOR_CARD = "#FFFFFF"\nCOR_BORDA = "#D7E1D7"\nCOR_SIDEBAR = "#EEF4EA"\nLOGO_FILE = Path("assets/logo_brasilata.png")\nDEFAULT_DATA_FILE = Path("data/qualidade/Consultas_RNC_APP.xlsx")\nMANUAL_FILE = Path("manual/Manual_BI_Qualidade_Corporativo_RM_2026.pdf")\n\n\n# =========================================================\n# Persistência de upload e estado\n# =========================================================\ndef _save_last_upload(xls_bytes: bytes, filename: str, sheet_name: str) -> None:\n    """Salva a última base enviada em local dedicado e mantém uma cópia padrão no diretório do app.\n\n    A cópia padrão funciona como redundância para quando a sessão do navegador expira\n    ou quando o app reinicia e precisa localizar automaticamente a última base disponível.\n    """\n    try:\n        LAST_DIR.mkdir(exist_ok=True)\n        LAST_FILE.write_bytes(xls_bytes)\n        LAST_META.write_text(\n            json.dumps({"filename": filename or "ultimo.xlsx", "sheet": sheet_name or DEFAULT_SHEET}, ensure_ascii=False, indent=2),\n            encoding="utf-8",\n        )\n    except Exception:\n        pass\n\n    # Redundância: mantém uma base padrão junto ao app para recuperação após inatividade/reinício.\n    try:\n        DEFAULT_DATA_FILE.write_bytes(xls_bytes)\n    except Exception:\n        pass\n\n\ndef _load_last_upload():\n    """Carrega a última base conhecida sem depender de st.session_state.\n\n    Ordem de busca:\n    1) .last_input/last_excel.bin, salvo no último upload;\n    2) Consultas_RNC_APP.xlsx no diretório do app, usado como fallback persistente do projeto.\n    """\n    try:\n        if LAST_FILE.exists() and LAST_FILE.stat().st_size > 0:\n            data = LAST_FILE.read_bytes()\n            meta = {}\n            if LAST_META.exists():\n                meta = json.loads(LAST_META.read_text(encoding="utf-8"))\n            return data, meta\n    except Exception:\n        pass\n\n    try:\n        if DEFAULT_DATA_FILE.exists() and DEFAULT_DATA_FILE.stat().st_size > 0:\n            return DEFAULT_DATA_FILE.read_bytes(), {"filename": DEFAULT_DATA_FILE.name, "sheet": DEFAULT_SHEET}\n    except Exception:\n        pass\n\n    return None, {}\n\n\ndef _save_state(state: dict) -> None:\n    try:\n        APP_STATE_FILE.write_text(json.dumps(state, ensure_ascii=False, indent=2), encoding="utf-8")\n    except Exception:\n        pass\n\n\ndef _load_state() -> dict:\n    try:\n        if APP_STATE_FILE.exists():\n            return json.loads(APP_STATE_FILE.read_text(encoding="utf-8"))\n    except Exception:\n        return {}\n    return {}\n\n# =========================================================\n# Funções de dados\n# =========================================================\ndef br_date_str(dt) -> str:\n    if pd.isna(dt):\n        return ""\n    try:\n        return pd.to_datetime(dt).strftime(DATE_FMT_BR)\n    except Exception:\n        return ""\n\n\ndef normalizar_situacao(x: str) -> str:\n    s = str(x).strip().upper()\n    if s in ("ATRASADA", "ATRASADO"):\n        return "ATRASADA"\n    if s in ("NO PRAZO", "NOPRAZO", "NO_PRAZO"):\n        return "NO PRAZO"\n    if s in ("", "NAN", "NONE"):\n        return ""\n    return s\n\n\n@st.cache_data(show_spinner=False)\ndef carregar_df(upload_bytes: bytes, sheet_name: str = DEFAULT_SHEET) -> pd.DataFrame:\n    # Leitura simplificada: o app não apresenta mais o campo "Nome da aba".\n    # Tenta abrir a aba padrão; se ela não existir, utiliza automaticamente a primeira aba da planilha.\n    try:\n        df = pd.read_excel(io.BytesIO(upload_bytes), sheet_name=sheet_name)\n    except Exception:\n        df = pd.read_excel(io.BytesIO(upload_bytes), sheet_name=0)\n\n    obrigatorias = [COL_CODIGO, COL_TITULO, COL_STATUS, COL_DATA, COL_MOTIVO]\n    faltantes = [c for c in obrigatorias if c not in df.columns]\n    if faltantes:\n        raise ValueError(f"Colunas obrigatórias não encontradas: {\', \'.join(faltantes)}")\n\n    df = df.copy()\n    df[COL_DATA] = pd.to_datetime(df[COL_DATA], errors="coerce", dayfirst=True)\n    df = df.dropna(subset=[COL_DATA])\n\n    for col in df.columns:\n        if df[col].dtype == "object":\n            df[col] = df[col].astype(str).str.strip().replace("nan", "")\n\n    if COL_SITUACAO in df.columns:\n        df[COL_SITUACAO] = df[COL_SITUACAO].apply(normalizar_situacao)\n\n    df["Ano"] = df[COL_DATA].dt.year.astype(int)\n    df["Mês Nº"] = df[COL_DATA].dt.month.astype(int)\n    df["Mês"] = df["Mês Nº"].map(MESES_ABREV)\n    df["Mês/Ano"] = df.apply(lambda r: f"{MESES_ABREV.get(int(r[\'Mês Nº\']), r[\'Mês Nº\'])}/{int(r[\'Ano\'])}", axis=1)\n    return df\n\n\ndef normalizar_meses_selecionados(meses) -> list[str]:\n    """Retorna lista válida de meses abreviados. Se vier vazio, considera todos os meses."""\n    todos = [MESES_ABREV[m] for m in range(1, 13)]\n    if meses is None:\n        return todos\n    if isinstance(meses, str):\n        meses = [meses]\n    meses = [str(m) for m in meses if str(m).strip()]\n    # Compatibilidade com versões antigas que tinham a opção (Todos).\n    if not meses or "(Todos)" in meses:\n        return todos\n    validos = [m for m in meses if m in INV_MESES_ABREV]\n    return validos or todos\n\n\ndef normalizar_anos_selecionados(anos, anos_disponiveis=None) -> list[int]:\n    """Retorna lista de anos válida. Se vier vazio ou (Todos), considera todos os anos disponíveis."""\n    if anos_disponiveis is None:\n        anos_disponiveis = []\n    if anos is None:\n        return [int(a) for a in anos_disponiveis]\n    if isinstance(anos, (str, int)):\n        anos = [anos]\n    anos_txt = [str(a).strip() for a in anos if str(a).strip()]\n    if not anos_txt or "(Todos)" in anos_txt:\n        return [int(a) for a in anos_disponiveis]\n    out = []\n    for a in anos_txt:\n        try:\n            out.append(int(a))\n        except Exception:\n            pass\n    return sorted(list(dict.fromkeys(out)))\n\n\ndef filtrar_periodo(df: pd.DataFrame, ano, meses) -> pd.DataFrame:\n    dff = df.copy()\n    anos_disponiveis = sorted(dff["Ano"].dropna().astype(int).unique().tolist())\n    anos_validos = normalizar_anos_selecionados(ano, anos_disponiveis)\n    if anos_validos:\n        dff = dff[dff["Ano"].isin(anos_validos)]\n    meses_validos = normalizar_meses_selecionados(meses)\n    meses_num = [INV_MESES_ABREV[m] for m in meses_validos]\n    dff = dff[dff["Mês Nº"].isin(meses_num)]\n    return dff\n\n\ndef aplicar_filtros_adicionais(df: pd.DataFrame, filtros: dict) -> pd.DataFrame:\n    dff = df.copy()\n    for col, selecionados in filtros.items():\n        if col not in dff.columns:\n            continue\n        if not selecionados:\n            return dff.iloc[0:0]\n        dff = dff[dff[col].astype(str).isin(selecionados)]\n    return dff\n\n\ndef resumo_periodo(df: pd.DataFrame) -> dict:\n    total = int(len(df))\n    atrasadas = 0\n    if COL_SITUACAO in df.columns and total:\n        atrasadas = int((df[COL_SITUACAO].apply(normalizar_situacao) == "ATRASADA").sum())\n    p_ini = br_date_str(df[COL_DATA].min()) if total else "-"\n    p_fim = br_date_str(df[COL_DATA].max()) if total else "-"\n    return {"total": total, "atrasadas": atrasadas, "periodo": f"{p_ini} → {p_fim}"}\n\n\ndef preparar_ocorrencias_normal(df: pd.DataFrame, ano_sel, mes_sel) -> pd.DataFrame:\n    """Prepara o gráfico normal para um ou vários anos/meses selecionados."""\n    if df.empty:\n        return pd.DataFrame({"Período": ["SEM DADOS"], "Ocorrências": [0]})\n\n    anos_validos = normalizar_anos_selecionados(ano_sel, sorted(df["Ano"].dropna().astype(int).unique().tolist()))\n    meses_validos = normalizar_meses_selecionados(mes_sel)\n\n    # Quando houver mais de um ano ou mais de um mês, mostrar evolução por mês/ano.\n    if len(anos_validos) > 1 or len(meses_validos) > 1:\n        base = df.copy()\n        g = base.groupby(["Ano", "Mês Nº", "Mês/Ano"], as_index=False).size().rename(columns={"size": "Ocorrências"})\n        g["_ordem"] = g["Ano"] * 100 + g["Mês Nº"]\n        g = g.sort_values("_ordem")\n        return g[["Mês/Ano", "Ocorrências"]].rename(columns={"Mês/Ano": "Período"})\n\n    label = periodo_label(anos_validos, meses_validos)\n    return pd.DataFrame({"Período": [label], "Ocorrências": [int(len(df))]})\n\n\ndef preparar_ocorrencias_por_mes_comparacao(df1: pd.DataFrame, label1: str, df2: pd.DataFrame, label2: str, meses_1, meses_2) -> pd.DataFrame:\n    """Base auxiliar para exportação: mostra a composição mensal de cada período comparado."""\n    linhas = []\n    for dfp, label, meses in [(df1, label1, meses_1), (df2, label2, meses_2)]:\n        meses_validos = normalizar_meses_selecionados(meses)\n        contagem = dfp.groupby("Mês Nº").size() if not dfp.empty else pd.Series(dtype=int)\n        for mes in meses_validos:\n            n = INV_MESES_ABREV[mes]\n            linhas.append({"Período": label, "Mês": mes, "Ocorrências": int(contagem.get(n, 0))})\n    return pd.DataFrame(linhas)\n\n\ndef preparar_motivos_normal(df: pd.DataFrame, top_n: int = 12) -> pd.DataFrame:\n    if df.empty:\n        return pd.DataFrame({"Motivo": ["SEM DADOS"], "Ocorrências": [0]})\n    g = df[COL_MOTIVO].fillna("").replace("", "SEM MOTIVO").value_counts().head(top_n).reset_index()\n    g.columns = ["Motivo", "Ocorrências"]\n    return g\n\n\ndef preparar_ocorrencias_comparacao(df1: pd.DataFrame, label1: str, df2: pd.DataFrame, label2: str) -> pd.DataFrame:\n    return pd.DataFrame(\n        {\n            "Período": [label1, label2],\n            "Ano": [label1, label2],\n            "Ocorrências": [int(len(df1)), int(len(df2))],\n        }\n    )\n\n\ndef preparar_motivos_comparacao(df1: pd.DataFrame, label1: str, df2: pd.DataFrame, label2: str, top_n: int = 12) -> pd.DataFrame:\n    m1 = df1[COL_MOTIVO].fillna("").replace("", "SEM MOTIVO").value_counts()\n    m2 = df2[COL_MOTIVO].fillna("").replace("", "SEM MOTIVO").value_counts()\n    motivos = (m1.add(m2, fill_value=0).sort_values(ascending=False).head(top_n).index.tolist())\n    linhas = []\n    for motivo in motivos:\n        linhas.append({"Motivo": motivo, "Período": label1, "Ocorrências": int(m1.get(motivo, 0))})\n        linhas.append({"Motivo": motivo, "Período": label2, "Ocorrências": int(m2.get(motivo, 0))})\n    if not linhas:\n        linhas = [\n            {"Motivo": "SEM DADOS", "Período": label1, "Ocorrências": 0},\n            {"Motivo": "SEM DADOS", "Período": label2, "Ocorrências": 0},\n        ]\n    return pd.DataFrame(linhas)\n\n\ndef periodo_label(ano, meses) -> str:\n    anos_validos = normalizar_anos_selecionados(ano, [])\n    if not anos_validos and isinstance(ano, list):\n        anos_validos = [int(a) for a in ano if str(a).isdigit()]\n    ano_txt = "+".join([str(a) for a in anos_validos]) if anos_validos else str(ano)\n    meses_validos = normalizar_meses_selecionados(meses)\n    todos = [MESES_ABREV[m] for m in range(1, 13)]\n    if meses_validos == todos:\n        return f"Ano {ano_txt}"\n    if len(meses_validos) == 1:\n        return f"{meses_validos[0]}/{ano_txt}"\n    return f"{\'+\'.join(meses_validos)}/{ano_txt}"\n\n\ndef calcular_variacao(valor_base: int, valor_comp: int) -> tuple[int, float]:\n    delta = int(valor_comp) - int(valor_base)\n    pct = (delta / int(valor_base) * 100) if int(valor_base) else 0.0\n    return delta, pct\n\n\ndef _formatar_planilha(ws):\n    thin = Side(style="thin", color="D9E2F3")\n    border = Border(left=thin, right=thin, top=thin, bottom=thin)\n    header_fill = PatternFill("solid", fgColor="1F4E79")\n    for row in ws.iter_rows():\n        for cell in row:\n            cell.border = border\n            cell.alignment = Alignment(vertical="center", wrap_text=True)\n    for cell in ws[1]:\n        cell.fill = header_fill\n        cell.font = Font(color="FFFFFF", bold=True)\n        cell.alignment = Alignment(horizontal="center", vertical="center", wrap_text=True)\n    # Ajuste compatível com Streamlit Cloud/openpyxl:\n    # em planilhas com células mescladas, col[0] pode ser MergedCell e não ter column_letter.\n    for col_idx, col in enumerate(ws.iter_cols(), start=1):\n        max_len = 10\n        letter = get_column_letter(col_idx)\n        for cell in col:\n            try:\n                max_len = max(max_len, len(str(cell.value)) if cell.value is not None else 0)\n            except Exception:\n                pass\n        ws.column_dimensions[letter].width = min(max_len + 2, 42)\n\n\ndef _adicionar_tabela(ws, df: pd.DataFrame, start_row: int = 1, start_col: int = 1):\n    for r_idx, row in enumerate(dataframe_to_rows(df, index=False, header=True), start=start_row):\n        for c_idx, value in enumerate(row, start=start_col):\n            ws.cell(row=r_idx, column=c_idx, value=value)\n    _formatar_planilha(ws)\n\n\ndef _formatar_recorte_compacto(ws, largura_padrao: float = 16, altura_padrao: float = 17, fonte_tamanho: int = 9):\n    """Formata a aba RECORTE com visual compacto e dimensões fixas.\n\n    Mantém fonte, altura de linha e largura de coluna padronizadas para evitar\n    variações causadas por textos longos. Colunas auxiliares são ocultadas.\n    """\n    thin = Side(style="thin", color="D9E2F3")\n    border = Border(left=thin, right=thin, top=thin, bottom=thin)\n    header_fill = PatternFill("solid", fgColor="1F4E79")\n\n    for row_idx, row in enumerate(ws.iter_rows(), start=1):\n        ws.row_dimensions[row_idx].height = altura_padrao\n        for cell in row:\n            cell.border = border\n            cell.font = Font(size=fonte_tamanho, color="1F2937")\n            cell.alignment = Alignment(\n                horizontal="left",\n                vertical="center",\n                wrap_text=False,\n                shrink_to_fit=True,\n            )\n\n    for cell in ws[1]:\n        cell.fill = header_fill\n        cell.font = Font(color="FFFFFF", bold=True, size=fonte_tamanho)\n        cell.alignment = Alignment(horizontal="center", vertical="center", wrap_text=False, shrink_to_fit=True)\n\n    # Dimensão fixa para todas as colunas; evita autoajuste que distorce a tabela.\n    for col_idx in range(1, ws.max_column + 1):\n        letter = get_column_letter(col_idx)\n        ws.column_dimensions[letter].width = largura_padrao\n\n    # Ajustes mínimos em colunas textuais principais, ainda com tamanho controlado.\n    cabecalhos = {ws.cell(row=1, column=c).value: c for c in range(1, ws.max_column + 1)}\n    larguras = {\n        COL_CODIGO: 11,\n        COL_DATA: 12,\n        COL_STATUS: 13,\n        COL_SITUACAO: 13,\n        COL_TITULO: 24,\n        COL_MOTIVO: 24,\n        COL_RESP_OCORRENCIA: 20,\n        COL_RESP_ANALISE: 22,\n        COL_CLIENTE: 20,\n        "Embalagem": 15,\n        "Período": 18,\n    }\n    for nome_coluna, largura in larguras.items():\n        if nome_coluna in cabecalhos:\n            ws.column_dimensions[get_column_letter(cabecalhos[nome_coluna])].width = largura\n\n    # Oculta colunas auxiliares/menos utilizadas no recorte exportado.\n    colunas_ocultar = {COL_CATEGORIA, "Local", "ANO", "Ano", "MÊS", "Mês", "MÊS Nº", "Mês Nº", "Mes", "Mes Nº"}\n    for nome_coluna, col_idx in cabecalhos.items():\n        if nome_coluna in colunas_ocultar:\n            ws.column_dimensions[get_column_letter(col_idx)].hidden = True\n\n    ws.freeze_panes = "A2"\n    ws.auto_filter.ref = ws.dimensions\n\n\ndef _preparar_figura_para_excel(fig, margem_inferior: int = 130):\n    """Replica a figura Plotly e aumenta a margem inferior para não cortar rótulos inclinados."""\n    try:\n        fig_excel = fig.full_copy()\n    except Exception:\n        try:\n            import copy\n            fig_excel = copy.deepcopy(fig)\n        except Exception:\n            fig_excel = fig\n    try:\n        fig_excel.update_xaxes(tickangle=-45, automargin=True)\n        fig_excel.update_layout(margin=dict(l=40, r=30, t=70, b=margem_inferior))\n    except Exception:\n        pass\n    return fig_excel\n\n\ndef _adicionar_grafico_barras(ws, title: str, cat_col: int, val_col: int, start_row: int, end_row: int, anchor: str, series_title_from_header: bool = True):\n    if end_row <= start_row:\n        return\n    chart = BarChart()\n    chart.type = "col"\n    chart.title = title\n    chart.height = 9\n    chart.width = 18\n    chart.legend = None\n    data = Reference(ws, min_col=val_col, min_row=start_row, max_row=end_row)\n    cats = Reference(ws, min_col=cat_col, min_row=start_row + 1, max_row=end_row)\n    chart.add_data(data, titles_from_data=series_title_from_header)\n    chart.set_categories(cats)\n    chart.dLbls = DataLabelList()\n    chart.dLbls.showVal = True\n    chart.dLbls.dLblPos = "outEnd"\n    try:\n        chart.y_axis.majorGridlines = None\n        chart.y_axis.tickLblPos = "none"\n    except Exception:\n        pass\n    try:\n        # Inclina os rótulos do eixo X em 45° para evitar corte/sobreposição.\n        chart.x_axis.textRotation = 45\n        chart.x_axis.tickLblPos = "low"\n    except Exception:\n        pass\n    ws.add_chart(chart, anchor)\n\n\ndef _adicionar_grafico_barras_multiserie(ws, title: str, cat_col: int, first_val_col: int, last_val_col: int, start_row: int, end_row: int, anchor: str):\n    """Adiciona gráfico de barras agrupadas com múltiplas séries.\n\n    Usado na comparação por período, mantendo o eixo X como Motivo ou Período\n    e cada período/ano como uma série distinta.\n    """\n    if end_row <= start_row or last_val_col < first_val_col:\n        return\n    chart = BarChart()\n    chart.type = "col"\n    chart.title = title\n    chart.height = 9\n    chart.width = 18\n    chart.legend = None if first_val_col == last_val_col else chart.legend\n    data = Reference(ws, min_col=first_val_col, max_col=last_val_col, min_row=start_row, max_row=end_row)\n    cats = Reference(ws, min_col=cat_col, min_row=start_row + 1, max_row=end_row)\n    chart.add_data(data, titles_from_data=True)\n    chart.set_categories(cats)\n    chart.dLbls = DataLabelList()\n    chart.dLbls.showVal = True\n    chart.dLbls.dLblPos = "outEnd"\n    try:\n        chart.y_axis.majorGridlines = None\n        chart.y_axis.tickLblPos = "none"\n    except Exception:\n        pass\n    try:\n        chart.x_axis.textRotation = 45\n        chart.x_axis.tickLblPos = "low"\n    except Exception:\n        pass\n    ws.add_chart(chart, anchor)\n\n\ndef _escrever_base_grafico(ws, df: pd.DataFrame, start_row: int, start_col: int):\n    for r_idx, row in enumerate(dataframe_to_rows(df, index=False, header=True), start=start_row):\n        for c_idx, value in enumerate(row, start=start_col):\n            ws.cell(row=r_idx, column=c_idx, value=value)\n    return start_row, start_col, start_row + len(df), start_col + df.shape[1] - 1\n\n\ndef gerar_relatorio_excel(\n    df_tabela: pd.DataFrame,\n    df_occ: pd.DataFrame,\n    df_mot: pd.DataFrame,\n    modo_comparacao: bool,\n    resumo_df: pd.DataFrame,\n    variacao_df: pd.DataFrame | None = None,\n    df_occ_mensal: pd.DataFrame | None = None,\n    figs_plotly: list | None = None,\n) -> bytes:\n    wb = Workbook()\n    ws_dash = wb.active\n    ws_dash.title = "DASHBOARD"\n    ws_dash.sheet_view.showGridLines = False\n\n    ws_resumo = wb.create_sheet("RESUMO")\n    _adicionar_tabela(ws_resumo, resumo_df)\n\n    ws_occ = wb.create_sheet("DADOS_OCORRENCIAS")\n    _adicionar_tabela(ws_occ, df_occ)\n\n    ws_mot = wb.create_sheet("DADOS_MOTIVOS")\n    _adicionar_tabela(ws_mot, df_mot)\n\n    if df_occ_mensal is not None and not df_occ_mensal.empty:\n        ws_mes = wb.create_sheet("COMPOSICAO_MENSAL")\n        _adicionar_tabela(ws_mes, df_occ_mensal)\n\n    if variacao_df is not None:\n        ws_var = wb.create_sheet("VARIACAO")\n        _adicionar_tabela(ws_var, variacao_df)\n\n    df_rec = df_tabela.copy()\n    if COL_DATA in df_rec.columns:\n        df_rec[COL_DATA] = df_rec[COL_DATA].apply(br_date_str)\n    ws_rec = wb.create_sheet("RECORTE")\n    _adicionar_tabela(ws_rec, df_rec)\n    _formatar_recorte_compacto(ws_rec)\n\n    # Dashboard sintético com os mesmos dados dos gráficos do app.\n    ws_dash["A1"] = "INDICADORES QUALIDADE RS — RELATÓRIO DO RECORTE"\n    ws_dash["A1"].font = Font(bold=True, size=16, color="1F4E79")\n    ws_dash.merge_cells("A1:H1")\n    ws_dash["A2"] = f"VERSÃO {APP_VERSION}"\n    ws_dash["A2"].font = Font(italic=True, size=10, color="666666")\n    ws_dash.merge_cells("A2:H2")\n    ws_dash["A3"] = "Resumo"\n    ws_dash["A3"].font = Font(bold=True, size=12)\n\n    # Copia resumo para o dashboard.\n    for r_idx, row in enumerate(dataframe_to_rows(resumo_df, index=False, header=True), start=4):\n        for c_idx, value in enumerate(row, start=1):\n            ws_dash.cell(row=r_idx, column=c_idx, value=value)\n\n    if variacao_df is not None:\n        base_row = 4 + len(resumo_df) + 3\n        ws_dash.cell(row=base_row, column=1, value="Variação entre períodos").font = Font(bold=True, size=12)\n        for r_idx, row in enumerate(dataframe_to_rows(variacao_df, index=False, header=True), start=base_row + 1):\n            for c_idx, value in enumerate(row, start=1):\n                ws_dash.cell(row=r_idx, column=c_idx, value=value)\n\n    _formatar_planilha(ws_dash)\n\n    # Gráficos em planilhas de dados.\n    # DADOS_OCORRENCIAS: Período no eixo X e rótulo sobre cada barra.\n    _adicionar_grafico_barras(\n        ws_occ,\n        "Número de ocorrências",\n        df_occ.columns.get_loc("Período") + 1 if "Período" in df_occ.columns else 1,\n        df_occ.columns.get_loc("Ocorrências") + 1,\n        1,\n        len(df_occ) + 1,\n        "E2",\n    )\n\n    # DADOS_MOTIVOS: Motivo no eixo X. Em comparação, monta base auxiliar\n    # agrupada por Período para barras de cores/séries distintas.\n    if modo_comparacao and "Período" in df_mot.columns:\n        df_mot_chart = (\n            df_mot.pivot_table(index="Motivo", columns="Período", values="Ocorrências", aggfunc="sum", fill_value=0)\n            .reset_index()\n        )\n        start_row, start_col = 1, max(8, df_mot.shape[1] + 3)\n        r1, c1, r2, c2 = _escrever_base_grafico(ws_mot, df_mot_chart, start_row, start_col)\n        _adicionar_grafico_barras_multiserie(\n            ws_mot,\n            "Motivos das ocorrências",\n            cat_col=c1,\n            first_val_col=c1 + 1,\n            last_val_col=c2,\n            start_row=r1,\n            end_row=r2,\n            anchor=f"{get_column_letter(c2 + 2)}2",\n        )\n    else:\n        _adicionar_grafico_barras(\n            ws_mot,\n            "Motivos das ocorrências",\n            df_mot.columns.get_loc("Motivo") + 1 if "Motivo" in df_mot.columns else 1,\n            df_mot.columns.get_loc("Ocorrências") + 1,\n            1,\n            len(df_mot) + 1,\n            "E2",\n        )\n\n    # Dashboard: insere os próprios gráficos Plotly apresentados na tela, preservando visual e cores.\n    imagens_inseridas = False\n    if figs_plotly:\n        anchors = ["A14", "J14"]\n        for fig, anchor in zip(figs_plotly, anchors):\n            try:\n                fig_excel = _preparar_figura_para_excel(fig)\n                img_bytes = io.BytesIO(fig_excel.to_image(format="png", scale=2))\n                img = XLImage(img_bytes)\n                img.width = 680\n                img.height = 410\n                ws_dash.add_image(img, anchor)\n                imagens_inseridas = True\n            except Exception:\n                imagens_inseridas = False\n                break\n\n    # Fallback: caso o ambiente não gere PNG pelo kaleido, cria gráficos nativos do Excel.\n    aux_row = 35\n    ws_dash.cell(row=aux_row, column=1, value="Base gráfico ocorrências").font = Font(bold=True)\n    for r_idx, row in enumerate(dataframe_to_rows(df_occ, index=False, header=True), start=aux_row + 1):\n        for c_idx, value in enumerate(row, start=1):\n            ws_dash.cell(row=r_idx, column=c_idx, value=value)\n    occ_val_col = df_occ.columns.get_loc("Ocorrências") + 1\n    if not imagens_inseridas:\n        _adicionar_grafico_barras(ws_dash, "Número de ocorrências", 1, occ_val_col, aux_row + 1, aux_row + len(df_occ) + 1, "A14")\n\n    aux_mot_row = aux_row + len(df_occ) + 15\n    ws_dash.cell(row=aux_mot_row, column=1, value="Base gráfico motivos").font = Font(bold=True)\n    for r_idx, row in enumerate(dataframe_to_rows(df_mot, index=False, header=True), start=aux_mot_row + 1):\n        for c_idx, value in enumerate(row, start=1):\n            ws_dash.cell(row=r_idx, column=c_idx, value=value)\n    mot_val_col = df_mot.columns.get_loc("Ocorrências") + 1\n    if not imagens_inseridas:\n        _adicionar_grafico_barras(ws_dash, "Motivos das ocorrências", 1, mot_val_col, aux_mot_row + 1, aux_mot_row + len(df_mot) + 1, "J14")\n\n    for ws in wb.worksheets:\n        ws.freeze_panes = "A2"\n\n    out = io.BytesIO()\n    wb.save(out)\n    out.seek(0)\n    return out.getvalue()\n\n\n# =========================================================\n# Manual integrado\n# =========================================================\ndef render_manual_app() -> None:\n    st.subheader("📘 Manual de funcionamento do aplicativo")\n    st.markdown(\n        """\n        **Aplicativo de consulta e análise de ocorrências por período e motivo.**\n\n        A base de dados deve ser retirada de consulta no sistema de gestão utilizado pela empresa,\n        exportada para Excel e carregada no aplicativo. Após o upload, o sistema mantém a última base\n        registrada para consulta automática na próxima abertura.\n        """\n    )\n\n    st.markdown("### Fluxo decisório de uso")\n    st.markdown(\n        """\n        1. **Preciso analisar ocorrências?**  \n           → Exporto a consulta do sistema de gestão para Excel.\n\n        2. **Tenho uma nova base?**  \n           → Sim: faço upload da nova planilha.  \n           → Não: o app utiliza automaticamente a última base registrada.\n\n        3. **Quero analisar um período único?**  \n           → Seleciono ano(s) e mês(es) na consulta normal.\n\n        4. **Quero comparar períodos?**  \n           → Ativo a análise comparativa, seleciono o(s) ano(s) do Período 1, os meses de análise e o(s) ano(s) do Período 2.  \n           → Os meses do Período 2 são sincronizados automaticamente com os meses do Período 1.\n\n        5. **Preciso investigar uma causa específica?**  \n           → Uso o filtro adicional por motivo.\n\n        6. **Preciso formalizar a análise?**  \n           → Uso o botão **Gerar relatório**, que exporta tabela, gráficos e variações em Excel.\n        """\n    )\n\n    st.markdown("### Tela do aplicativo — campos principais")\n    st.info(\n        "1) Upload da base Excel | 2) Filtros de ano e mês | 3) Comparação entre períodos | "\n        "4) Filtro por motivo | 5) Total de ocorrências | 6) Gráfico por período | "\n        "7) Gráfico por motivo | 8) Gerar relatório"\n    )\n\n    st.markdown("### Leitura dos gráficos")\n    st.markdown(\n        """\n        - **Número de ocorrências:** mostra o volume de ocorrências no período selecionado ou a comparação entre períodos.\n        - **Motivos das ocorrências:** mostra os principais motivos registrados na base filtrada.\n        - **Variação entre períodos:** em análise comparativa, indica aumento ou redução entre os períodos selecionados.\n        """\n    )\n\n    if MANUAL_FILE.exists():\n        with open(MANUAL_FILE, "rb") as f:\n            st.download_button(\n                "📥 Baixar manual completo em PDF",\n                data=f,\n                file_name="Manual_APP_Indicadores_Qualidade_V_RM_2026.pdf",\n                mime="application/pdf",\n            )\n    else:\n        st.warning("Manual PDF não encontrado no diretório do app. A orientação resumida permanece disponível nesta aba.")\n\n# =========================================================\n# Interface\n# =========================================================\nst.set_page_config(page_title=APP_NAME, page_icon="📊", layout="wide")\nst.markdown(\n    f"""\n    <style>\n    .stApp {{background: linear-gradient(180deg, {COR_FUNDO} 0%, {COR_FUNDO_2} 38%, #FFFFFF 100%); color: {COR_TEXTO};}}\n    .block-container {{padding-top: 1rem; padding-bottom: 1rem;}}\n    h1, h2, h3, .stMarkdown, label, p {{color: {COR_TEXTO};}}\n    div[data-testid="stMetric"] {{background-color: {COR_CARD}; border: 1px solid {COR_BORDA}; border-radius: 16px; padding: 14px; box-shadow: 0 6px 18px rgba(23,61,53,0.08);}}\n    div[data-testid="stMetricLabel"] p {{color: {COR_TEXTO}; font-weight: 700;}}\n    section[data-testid="stSidebar"] {{background: linear-gradient(180deg, {COR_SIDEBAR} 0%, #FFFFFF 100%); border-right: 1px solid {COR_BORDA};}}\n    div[data-testid="stExpander"] {{background-color: rgba(255,255,255,0.72); border-radius: 14px; border: 1px solid {COR_BORDA};}}\n    .main-title {{display:flex; align-items:center; gap:18px; margin-bottom: 0.4rem;}}\n    .main-title img {{width:130px; border-radius: 8px;}}\n    .main-title h1 {{margin:0; color:{COR_TEXTO};}}\n    @media (max-width: 768px) {{\n        .block-container {{padding-left: 0.75rem; padding-right: 0.75rem;}}\n        div[data-testid="stHorizontalBlock"] {{flex-direction: column !important;}}\n        .main-title {{flex-direction:column; align-items:flex-start;}}\n    }}\n    </style>\n    """,\n    unsafe_allow_html=True,\n)\n\nlogo_path = LOGO_FILE if LOGO_FILE.exists() else Path("/mnt/data/images.png")\ncol_logo, col_title = st.columns([0.8, 5])\nwith col_logo:\n    if logo_path.exists():\n        st.image(str(logo_path), width=125)\nwith col_title:\n    st.title(APP_NAME)\n    st.markdown(\n        """\n        **APLICATIVO DE CONSULTA E ANÁLISE DE OCORRÊNCIAS POR PERÍODO E MOTIVO.**  \n        Em filtros adicionais é possível filtrar as ocorrências por motivo do período selecionado.\n        """\n    )\n    st.markdown(f"<div style=\'font-size:10px; font-style:italic; font-weight:600; letter-spacing:0.04em;\'>VERSÃO {APP_VERSION}</div>", unsafe_allow_html=True)\n\nwith st.expander("📘 Manual", expanded=False):\n    render_manual_app()\n\nsaved_state = _load_state()\nlast_bytes, last_meta = _load_last_upload()\n\nwith st.sidebar:\n    st.header("📥 Base de dados")\n    sheet = DEFAULT_SHEET\n    up = st.file_uploader("Enviar nova base Excel", type=["xlsx", "xlsm", "xls"])\n\n    if last_bytes and up is None:\n        st.success(f"Base carregada automaticamente: {last_meta.get(\'filename\', \'ultimo.xlsx\')}")\n    elif up is not None:\n        st.success(f"Novo upload recebido: {up.name}")\n    else:\n        st.info("Envie uma base Excel para iniciar.")\n\nif up is not None:\n    upload_bytes = up.getvalue()\n    upload_name = up.name\nelse:\n    upload_bytes = last_bytes\n    upload_name = last_meta.get("filename", "ultimo.xlsx") if last_bytes else None\n\nif not upload_bytes or len(upload_bytes) == 0:\n    st.warning("Nenhuma base disponível. Faça upload da consulta exportada do sistema de gestão.")\n    st.stop()\n\ntry:\n    df_base = carregar_df(upload_bytes, sheet)\n    _save_last_upload(upload_bytes, upload_name or "ultimo.xlsx", sheet)\nexcept Exception as e:\n    st.error(f"Erro ao carregar a base: {e}")\n    st.stop()\n\nanos = sorted([int(a) for a in df_base["Ano"].dropna().unique().tolist() if int(a) >= 2025])\nif not anos:\n    st.warning("A base não possui registros a partir de 2025.")\n    st.stop()\n\nmes_options = [MESES_ABREV[m] for m in range(1, 13)]\nano_options = [str(a) for a in anos]\n\nst.subheader("Filtros")\nst.caption("Ao abrir o aplicativo, a consulta inicia sem comparação, considerando todos os anos e meses existentes na última base carregada.")\nmodo_comparacao = st.toggle(\n    "Ativar análise comparativa entre períodos",\n    value=False,\n    key="modo_comparacao_toggle",\n)\n\nif not modo_comparacao:\n    c1, c2 = st.columns(2)\n    with c1:\n        ano_sel = st.multiselect(\n            "Ano(s)",\n            options=ano_options,\n            default=ano_options,\n            key="ano_sel_normal",\n            help="Por padrão, todos os anos da base ficam selecionados.",\n        )\n    with c2:\n        mes_sel = st.multiselect(\n            "Mês(es)",\n            options=mes_options,\n            default=mes_options,\n            key="mes_sel_normal",\n            help="Por padrão, todos os meses ficam selecionados. Remova os meses que não deseja analisar.",\n        )\nelse:\n    st.markdown("**Período 1 x Período 2**")\n    st.caption("Selecione os meses somente no Período 1. O Período 2 usa automaticamente os mesmos meses, mudando apenas o(s) ano(s) de referência.")\n    meses_multiselect = mes_options\n    c1, c2, c3, c4 = st.columns([1, 2, 1, 2])\n    with c1:\n        ano_1 = st.multiselect(\n            "Ano(s) — Período 1",\n            ano_options,\n            default=[ano_options[0]],\n            key="ano_1_comp",\n        )\n    with c2:\n        mes_1 = st.multiselect(\n            "Meses de comparação",\n            meses_multiselect,\n            default=["Jan"],\n            key="mes_1_comp",\n        )\n    with c3:\n        ano_2 = st.multiselect(\n            "Ano(s) — Período 2",\n            ano_options,\n            default=[ano_options[-1]],\n            key="ano_2_comp",\n        )\n    with c4:\n        mes_2 = list(mes_1) if mes_1 else meses_multiselect\n        st.write("**Meses — Período 2 (automático)**")\n        st.info(", ".join(mes_2))\n        st.caption("Meses sincronizados com o Período 1.")\n\nwith st.expander("Filtros adicionais", expanded=False):\n    filtros = {}\n    # Categoria removida dos filtros adicionais. Motivo incluído para permitir consulta direta por motivo no período selecionado.\n    cols_filtro = [c for c in [COL_STATUS, COL_MOTIVO, COL_CLIENTE, COL_RESP_OCORRENCIA, COL_RESP_ANALISE, COL_SITUACAO] if c in df_base.columns]\n    grid = st.columns(3)\n    for i, col in enumerate(cols_filtro):\n        valores = sorted([v for v in df_base[col].dropna().astype(str).replace("nan", "").unique().tolist() if v != ""])\n        default = valores\n        with grid[i % 3]:\n            filtros[col] = st.multiselect(col, options=valores, default=default)\n\n# Aplica filtros adicionais antes do recorte por período, para todos os gráficos respeitarem o mesmo escopo.\ndf_escopo = aplicar_filtros_adicionais(df_base, filtros)\n\nif not modo_comparacao:\n    df_periodo = filtrar_periodo(df_escopo, ano_sel, mes_sel)\n    resumo = resumo_periodo(df_periodo)\n\n    k1, k2, k3, k4 = st.columns(4)\n    k1.metric("Ocorrências", resumo["total"])\n    k2.metric("Em atraso", resumo["atrasadas"])\n    k3.metric("Período", resumo["periodo"])\n    k4.metric("Base ativa", upload_name or "último upload")\n\n    st.divider()\n    st.subheader("Número de ocorrências")\n    df_occ = preparar_ocorrencias_normal(df_periodo, ano_sel, mes_sel)\n    fig1 = px.bar(df_occ, x="Período", y="Ocorrências", text="Ocorrências", title=f"Ocorrências — {periodo_label(ano_sel, mes_sel)}")\n    fig1.update_traces(marker_color=COR_NORMAL, textposition="outside", cliponaxis=False)\n    fig1.update_yaxes(title=None, showticklabels=False)\n    fig1.update_layout(showlegend=False, height=430, margin=dict(l=10, r=10, t=55, b=10))\n    st.plotly_chart(fig1, use_container_width=True)\n\n    st.subheader("Motivos das ocorrências")\n    df_mot = preparar_motivos_normal(df_periodo)\n    fig2 = px.bar(df_mot, x="Motivo", y="Ocorrências", text="Ocorrências", title="Motivos — Top 12")\n    fig2.update_traces(marker_color=COR_NORMAL, textposition="outside", cliponaxis=False)\n    fig2.update_layout(xaxis_tickangle=-45, showlegend=False, height=460, margin=dict(l=10, r=10, t=55, b=10))\n    fig2.update_yaxes(title=None, showticklabels=False)\n    st.plotly_chart(fig2, use_container_width=True)\n\n    df_tabela = df_periodo.sort_values(COL_DATA, ascending=False)\n    resumo_export = pd.DataFrame([{"Período": periodo_label(ano_sel, mes_sel), "Ocorrências": resumo["total"], "Atrasadas": resumo["atrasadas"], "Intervalo": resumo["periodo"]}])\n    df_variacao = None\n    df_occ_mensal = None\n    state_to_save = {"sheet": sheet, "modo_comparacao": False, "ano_sel": ano_sel, "mes_sel": mes_sel, "filtros": filtros}\n\nelse:\n    df_p1 = filtrar_periodo(df_escopo, ano_1, mes_1)\n    df_p2 = filtrar_periodo(df_escopo, ano_2, mes_2)\n    label1 = periodo_label(ano_1, mes_1)\n    label2 = periodo_label(ano_2, mes_2)\n\n    r1 = resumo_periodo(df_p1)\n    r2 = resumo_periodo(df_p2)\n    variacao, variacao_pct = calcular_variacao(r1["total"], r2["total"])\n    variacao_atrasadas, variacao_atrasadas_pct = calcular_variacao(r1["atrasadas"], r2["atrasadas"])\n    df_variacao = pd.DataFrame([\n        {"Indicador": "Ocorrências", "Período 1": r1["total"], "Período 2": r2["total"], "Variação absoluta": variacao, "Variação %": round(variacao_pct, 1)},\n        {"Indicador": "Atrasadas", "Período 1": r1["atrasadas"], "Período 2": r2["atrasadas"], "Variação absoluta": variacao_atrasadas, "Variação %": round(variacao_atrasadas_pct, 1)},\n    ])\n    df_occ_mensal = preparar_ocorrencias_por_mes_comparacao(df_p1, label1, df_p2, label2, mes_1, mes_2)\n\n    k1, k2, k3, k4 = st.columns(4)\n    k1.metric(label1, r1["total"])\n    k2.metric(label2, r2["total"], delta=variacao)\n    k3.metric("Variação %", f"{variacao_pct:.1f}%")\n    k4.metric("Base ativa", upload_name or "último upload")\n\n    with st.expander("Dados da variação entre períodos", expanded=False):\n        st.dataframe(df_variacao, use_container_width=True, hide_index=True)\n\n    st.divider()\n    st.subheader("Número de ocorrências")\n    df_occ = preparar_ocorrencias_comparacao(df_p1, label1, df_p2, label2)\n    fig1 = px.bar(\n        df_occ,\n        x="Período",\n        y="Ocorrências",\n        color="Período",\n        text="Ocorrências",\n        title=f"Comparação de ocorrências — {label1} x {label2}",\n        color_discrete_sequence=CORES_COMPARACAO,\n    )\n    fig1.update_traces(textposition="outside", cliponaxis=False)\n    fig1.update_yaxes(title=None, showticklabels=False)\n    fig1.update_layout(showlegend=True, height=430, margin=dict(l=10, r=10, t=55, b=10))\n    st.plotly_chart(fig1, use_container_width=True)\n\n    st.subheader("Motivos das ocorrências")\n    df_mot = preparar_motivos_comparacao(df_p1, label1, df_p2, label2)\n    fig2 = px.bar(\n        df_mot,\n        x="Motivo",\n        y="Ocorrências",\n        color="Período",\n        barmode="group",\n        text="Ocorrências",\n        title=f"Comparação dos motivos — {label1} x {label2}",\n        color_discrete_sequence=CORES_COMPARACAO,\n    )\n    fig2.update_traces(textposition="outside", cliponaxis=False)\n    fig2.update_layout(xaxis_tickangle=-45, showlegend=True, height=500, margin=dict(l=10, r=10, t=55, b=10))\n    fig2.update_yaxes(title=None, showticklabels=False)\n    st.plotly_chart(fig2, use_container_width=True)\n\n    df_tabela = pd.concat([\n        df_p1.assign(Período=label1),\n        df_p2.assign(Período=label2),\n    ], ignore_index=True).sort_values(COL_DATA, ascending=False)\n    resumo_export = pd.DataFrame([\n        {"Período": label1, "Ocorrências": r1["total"], "Atrasadas": r1["atrasadas"], "Intervalo": r1["periodo"]},\n        {"Período": label2, "Ocorrências": r2["total"], "Atrasadas": r2["atrasadas"], "Intervalo": r2["periodo"]},\n    ])\n    state_to_save = {\n        "sheet": sheet,\n        "modo_comparacao": True,\n        "ano_1": ano_1,\n        "mes_1": mes_1,\n        "ano_2": ano_2,\n        "mes_2": mes_2,\n        "filtros": filtros,\n    }\n\n_save_state(state_to_save)\n\nst.divider()\nwith st.expander("Tabela do recorte", expanded=False):\n    st.dataframe(df_tabela, use_container_width=True, height=360)\n    st.download_button(\n        "📥 Gerar relatório",\n        data=gerar_relatorio_excel(\n            df_tabela=df_tabela,\n            df_occ=df_occ,\n            df_mot=df_mot,\n            modo_comparacao=modo_comparacao,\n            resumo_df=resumo_export,\n            variacao_df=df_variacao if modo_comparacao else None,\n            df_occ_mensal=df_occ_mensal if modo_comparacao else None,\n            figs_plotly=[fig1, fig2],\n        ),\n        file_name=f"relatorio_indicadores_qualidade_{APP_VERSION}.xlsx",\n        mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",\n    )\n',
    'sqdcp.py': 'from __future__ import annotations\n\nimport base64\nimport os\nfrom datetime import date, datetime\nfrom io import BytesIO\nfrom pathlib import Path\nfrom typing import Optional, Tuple\n\nimport pandas as pd\nimport plotly.graph_objects as go\nimport requests\nimport streamlit as st\n\nst.set_page_config(page_title="FMDS SQDCP", page_icon="📊", layout="wide")\n\nst.markdown("""\n<style>\n.stApp {\n    background-color: #80EF80;\n}\n.block-container {\n    background: rgba(255, 255, 255, 0.88);\n    border-radius: 18px;\n    padding-top: 2rem;\n    padding-bottom: 2rem;\n}\nsection[data-testid="stSidebar"] > div {\n    background-color: #EFFFF0;\n}\n</style>\n""", unsafe_allow_html=True)\n\n# =====================================================\n# Configuração de persistência\n# =====================================================\nLOCAL_DATA_DIR = Path("data/sqdcp")\nLOCAL_DATA_DIR.mkdir(exist_ok=True)\nLOCAL_DB_FILE = LOCAL_DATA_DIR / "sqdcp_base.xlsx"\n\nDATA_SHEET = "dados"\nACTIONS_SHEET = "acoes"\nMETAS_SHEET = "metas"\n\nINDICADORES = [\n    "Acidentes",\n    "Reclamações",\n    "Perda",\n    "Atendimento no prazo",\n    "Eficiência",\n]\n\nCOLS_DADOS = [\n    "data",\n    "acidentes_un",\n    "reclamacoes_un",\n    "perda_prensas_t",\n    "perda_litografia_t",\n    "perda_montagem_t",\n    "atendimento_prazo_pct",\n    "eficiencia_prensas_pct",\n    "eficiencia_litografia_pct",\n    "eficiencia_montagem_pct",\n]\n\nCOLS_ACOES = [\n    "indicador",\n    "descricao",\n    "responsavel",\n    "prazo",\n    "status",\n]\n\nCOLS_METAS = [\n    "indicador",\n    "meta",\n    "unidade",\n    "tipo",\n]\n\nMETAS_PADRAO = pd.DataFrame([\n    {"indicador": "Acidentes", "meta": 0.0, "unidade": "un", "tipo": "menor_melhor"},\n    {"indicador": "Reclamações", "meta": 0.0, "unidade": "un", "tipo": "menor_melhor"},\n    {"indicador": "Perda", "meta": 0.0, "unidade": "t", "tipo": "menor_melhor"},\n    {"indicador": "Atendimento no prazo", "meta": 100.0, "unidade": "%", "tipo": "maior_melhor"},\n    {"indicador": "Eficiência", "meta": 100.0, "unidade": "%", "tipo": "maior_melhor"},\n])\n\n\ndef get_secret(name: str, default: str = "") -> str:\n    try:\n        return str(st.secrets.get(name, default))\n    except Exception:\n        return os.getenv(name, default)\n\n\nGITHUB_TOKEN = get_secret("GITHUB_TOKEN")\nGITHUB_REPO = get_secret("GITHUB_REPO")  # exemplo: usuario/repositorio\nGITHUB_BRANCH = get_secret("GITHUB_BRANCH", "main")\nGITHUB_FILE_PATH = get_secret("GITHUB_FILE_PATH", "data/sqdcp/sqdcp_base.xlsx")\n\n\ndef github_enabled() -> bool:\n    return bool(GITHUB_TOKEN and GITHUB_REPO and GITHUB_BRANCH and GITHUB_FILE_PATH)\n\n\ndef github_headers() -> dict:\n    return {\n        "Authorization": f"Bearer {GITHUB_TOKEN}",\n        "Accept": "application/vnd.github+json",\n        "X-GitHub-Api-Version": "2022-11-28",\n    }\n\n\ndef github_api_url() -> str:\n    return f"https://api.github.com/repos/{GITHUB_REPO}/contents/{GITHUB_FILE_PATH}"\n\n\ndef read_github_file() -> Tuple[Optional[bytes], Optional[str], Optional[str]]:\n    if not github_enabled():\n        return None, None, "Persistência GitHub não configurada. Usando arquivo local temporário."\n    try:\n        r = requests.get(\n            github_api_url(),\n            headers=github_headers(),\n            params={"ref": GITHUB_BRANCH},\n            timeout=20,\n        )\n        if r.status_code == 404:\n            return None, None, None\n        r.raise_for_status()\n        payload = r.json()\n        content = base64.b64decode(payload["content"])\n        return content, payload.get("sha"), None\n    except Exception as exc:\n        return None, None, f"Não foi possível ler a base no GitHub: {exc}"\n\n\ndef write_github_file(file_bytes: bytes, message: str = "Atualiza base SQDCP FMDS") -> Optional[str]:\n    if not github_enabled():\n        return "Persistência GitHub não configurada. Dados salvos apenas no arquivo local da sessão."\n    _, sha, _ = read_github_file()\n    payload = {\n        "message": message,\n        "content": base64.b64encode(file_bytes).decode("utf-8"),\n        "branch": GITHUB_BRANCH,\n    }\n    if sha:\n        payload["sha"] = sha\n    try:\n        r = requests.put(github_api_url(), headers=github_headers(), json=payload, timeout=25)\n        r.raise_for_status()\n        return None\n    except Exception as exc:\n        return f"Não foi possível gravar a base no GitHub: {exc}"\n\n\ndef empty_dados() -> pd.DataFrame:\n    df = pd.DataFrame(columns=COLS_DADOS)\n    df["data"] = pd.to_datetime(df["data"])\n    return df\n\n\ndef empty_acoes() -> pd.DataFrame:\n    return pd.DataFrame(columns=COLS_ACOES)\n\n\ndef empty_metas() -> pd.DataFrame:\n    return METAS_PADRAO.copy()\n\n\ndef normalize_dados(df: pd.DataFrame) -> pd.DataFrame:\n    df = df.copy()\n    # Compatibilidade: bases antigas podem conter a coluna "semana"; ela é ignorada nesta versão.\n    for col in COLS_DADOS:\n        if col not in df.columns:\n            df[col] = 0 if col != "data" else pd.NaT\n    df = df[COLS_DADOS]\n    df["data"] = pd.to_datetime(df["data"], errors="coerce", dayfirst=True)\n    df = df.dropna(subset=["data"])\n    numeric_cols = [c for c in COLS_DADOS if c != "data"]\n    for col in numeric_cols:\n        df[col] = pd.to_numeric(df[col], errors="coerce").fillna(0.0)\n    return df\n\n\ndef normalize_acoes(df: pd.DataFrame) -> pd.DataFrame:\n    df = df.copy()\n    for col in COLS_ACOES:\n        if col not in df.columns:\n            df[col] = ""\n    df = df[COLS_ACOES]\n    df["indicador"] = df["indicador"].fillna("").astype(str)\n    df["descricao"] = df["descricao"].fillna("").astype(str)\n    df["responsavel"] = df["responsavel"].fillna("").astype(str)\n    df["prazo"] = pd.to_datetime(df["prazo"], errors="coerce", dayfirst=True)\n    df["status"] = df["status"].fillna("").astype(str)\n    return df\n\n\ndef normalize_metas(df: pd.DataFrame) -> pd.DataFrame:\n    if df is None or df.empty:\n        return empty_metas()\n    df = df.copy()\n    for col in COLS_METAS:\n        if col not in df.columns:\n            df[col] = ""\n    df = df[COLS_METAS]\n    df["indicador"] = df["indicador"].fillna("").astype(str)\n    df["meta"] = pd.to_numeric(df["meta"], errors="coerce").fillna(0.0)\n    df["unidade"] = df["unidade"].fillna("").astype(str)\n    df["tipo"] = df["tipo"].fillna("").astype(str)\n\n    base = empty_metas()\n    atual = df[df["indicador"].isin(INDICADORES)].copy()\n    if not atual.empty:\n        base = base[~base["indicador"].isin(atual["indicador"])]\n        base = pd.concat([base, atual], ignore_index=True)\n    base = base.drop_duplicates(subset=["indicador"], keep="last")\n    return base[COLS_METAS]\n\n\ndef get_meta(metas: pd.DataFrame, indicador: str, default: float = 0.0) -> float:\n    metas = normalize_metas(metas)\n    linha = metas[metas["indicador"] == indicador]\n    if linha.empty:\n        return default\n    return float(linha["meta"].iloc[0])\n\n\ndef read_workbook(file_bytes: bytes) -> Tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:\n    bio = BytesIO(file_bytes)\n    xls = pd.ExcelFile(bio, engine="openpyxl")\n    dados = pd.read_excel(xls, DATA_SHEET) if DATA_SHEET in xls.sheet_names else empty_dados()\n    acoes = pd.read_excel(xls, ACTIONS_SHEET) if ACTIONS_SHEET in xls.sheet_names else empty_acoes()\n    metas = pd.read_excel(xls, METAS_SHEET) if METAS_SHEET in xls.sheet_names else empty_metas()\n    return normalize_dados(dados), normalize_acoes(acoes), normalize_metas(metas)\n\n\ndef to_workbook_bytes(dados: pd.DataFrame, acoes: pd.DataFrame, metas: Optional[pd.DataFrame] = None) -> bytes:\n    dados = normalize_dados(dados)\n    acoes = normalize_acoes(acoes)\n    metas = normalize_metas(metas if metas is not None else empty_metas())\n    output = BytesIO()\n    with pd.ExcelWriter(output, engine="openpyxl") as writer:\n        dados.to_excel(writer, sheet_name=DATA_SHEET, index=False)\n        acoes.to_excel(writer, sheet_name=ACTIONS_SHEET, index=False)\n        metas.to_excel(writer, sheet_name=METAS_SHEET, index=False)\n    output.seek(0)\n    return output.getvalue()\n\n\ndef load_base() -> Tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame, list[str]]:\n    avisos = []\n    file_bytes, _, warn = read_github_file()\n    if warn:\n        avisos.append(warn)\n    if file_bytes:\n        try:\n            LOCAL_DB_FILE.write_bytes(file_bytes)\n            dados, acoes, metas = read_workbook(file_bytes)\n            return dados, acoes, metas, avisos\n        except Exception as exc:\n            avisos.append(f"A base no GitHub existe, mas não pôde ser lida: {exc}")\n    if LOCAL_DB_FILE.exists():\n        try:\n            dados, acoes, metas = read_workbook(LOCAL_DB_FILE.read_bytes())\n            return dados, acoes, metas, avisos\n        except Exception as exc:\n            avisos.append(f"A base local não pôde ser lida: {exc}")\n    return empty_dados(), empty_acoes(), empty_metas(), avisos\n\n\ndef save_base(dados: pd.DataFrame, acoes: pd.DataFrame, metas: Optional[pd.DataFrame] = None) -> Optional[str]:\n    file_bytes = to_workbook_bytes(dados, acoes, metas)\n    LOCAL_DB_FILE.parent.mkdir(exist_ok=True)\n    LOCAL_DB_FILE.write_bytes(file_bytes)\n    return write_github_file(file_bytes)\n\n\ndef month_name(n: int) -> str:\n    nomes = ["Jan", "Fev", "Mar", "Abr", "Mai", "Jun", "Jul", "Ago", "Set", "Out", "Nov", "Dez"]\n    return nomes[n - 1]\n\ndef month_year_label(value) -> str:\n    """Retorna mês/ano abreviado para exibição simples: Jan/2026."""\n    try:\n        ts = pd.to_datetime(value)\n        return f"{month_name(int(ts.month))}/{int(ts.year)}"\n    except Exception:\n        return str(value)\n\n\ndef gauge_status_color(value: float, meta: float, tipo: str) -> str:\n    """Cor do marcador do relógio: verde quando atende a meta, vermelho quando não atende."""\n    value = float(value or 0)\n    meta = float(meta or 0)\n    if tipo == "menor_melhor":\n        return "#2ca02c" if value <= meta else "#d62728"\n    return "#2ca02c" if value >= meta else "#d62728"\n\n\ndef gauge(title: str, value: float, unit: str, min_value: float, max_value: float, meta: float, tipo: str) -> go.Figure:\n    """Relógio com faixas visuais calibradas pela meta do indicador."""\n    value = float(value or 0)\n    meta = float(meta or 0)\n    if max_value <= min_value:\n        max_value = min_value + 1\n\n    steps = [\n        {"range": [min_value, max_value], "color": "#f2f2f2"},\n    ]\n\n    fig = go.Figure(go.Indicator(\n        mode="gauge+number",\n        value=value,\n        number={"suffix": f" {unit}"},\n        title={"text": title, "font": {"size": 18}},\n        gauge={\n            "axis": {"range": [min_value, max_value]},\n            "bar": {"color": gauge_status_color(value, meta, tipo)},\n            "threshold": {\n                "line": {"color": "#111111", "width": 3},\n                "thickness": 0.75,\n                "value": min(max_value, max(min_value, meta)),\n            },\n            "steps": steps,\n        },\n    ))\n    fig.update_layout(height=260, margin=dict(l=10, r=10, t=40, b=10))\n    return fig\n\n\n\ndef auto_y_range(values, meta=None, min_floor: float = 0.0):\n    """Escala automática para evidenciar variações da série histórica."""\n    serie = pd.Series(values).dropna().astype(float)\n    pontos = serie.tolist()\n    if meta is not None and pd.notna(meta):\n        pontos.append(float(meta))\n    if not pontos:\n        return [0, 1]\n    menor = min(pontos)\n    maior = max(pontos)\n    if menor == maior:\n        margem = max(abs(maior) * 0.10, 1.0)\n    else:\n        margem = (maior - menor) * 0.20\n    y_min = max(min_floor, menor - margem)\n    y_max = maior + margem\n    if y_max <= y_min:\n        y_max = y_min + 1\n    return [y_min, y_max]\ndef status_sinaleira(status: str) -> str:\n    status_original = str(status or "").strip()\n    status_norm = status_original.lower()\n    if status_norm in ["", "null", "sem ação", "sem acao", "nenhuma"]:\n        return ""\n    if status_norm in ["concluída", "concluida"]:\n        return "🟢 Concluída"\n    if status_norm == "em andamento":\n        return "🟡 Em andamento"\n    if status_norm == "aberta":\n        return "🔴 Aberta"\n    return status_original\n\n\ndef sinaleira_to_status(sinaleira: str) -> str:\n    valor = str(sinaleira or "").strip()\n    if valor in ["", "null", "Sem ação", "Sem acao"]:\n        return ""\n    return (\n        valor.replace("🔴 ", "", 1)\n        .replace("🟡 ", "", 1)\n        .replace("🟢 ", "", 1)\n        .strip()\n    )\n\ndef build_template() -> bytes:\n    modelo_dados = pd.DataFrame([{\n        "data": date.today(),\n        "acidentes_un": 0,\n        "reclamacoes_un": 0,\n        "perda_prensas_t": 0.0,\n        "perda_litografia_t": 0.0,\n        "perda_montagem_t": 0.0,\n        "atendimento_prazo_pct": 100.0,\n        "eficiencia_prensas_pct": 0.0,\n        "eficiencia_litografia_pct": 0.0,\n        "eficiencia_montagem_pct": 0.0,\n    }])\n    modelo_acoes = pd.DataFrame(columns=COLS_ACOES)\n    modelo_metas = empty_metas()\n    return to_workbook_bytes(modelo_dados, modelo_acoes, modelo_metas)\n\n\n# =====================================================\n# Interface\n# =====================================================\nst.title("📊 FMDS SQDCP - Painel Industrial")\nst.caption("Visualização simples, lançamento em massa e base persistente via GitHub.")\n\nif "loaded" not in st.session_state:\n    dados, acoes, metas, avisos = load_base()\n    st.session_state["dados"] = dados\n    st.session_state["acoes"] = acoes\n    st.session_state["metas"] = metas\n    st.session_state["avisos"] = avisos\n    st.session_state["loaded"] = True\n\nfor aviso in st.session_state.get("avisos", []):\n    st.warning(aviso)\n\nif github_enabled():\n    st.success(f"Persistência GitHub ativa: {GITHUB_REPO}/{GITHUB_FILE_PATH}")\nelse:\n    st.info("Persistência GitHub ainda não configurada. Configure os Secrets no Streamlit Cloud para salvar a base definitivamente.")\n\nwith st.sidebar:\n    st.header("Filtros")\n    dados_base = normalize_dados(st.session_state["dados"])\n    if dados_base.empty:\n        periodos_disp = [pd.Period(date.today(), freq="M")]\n    else:\n        periodos_disp = sorted(dados_base["data"].dt.to_period("M").dropna().unique().tolist())\n        if not periodos_disp:\n            periodos_disp = [pd.Period(date.today(), freq="M")]\n    periodo_sel = st.selectbox(\n        "Mês/Ano",\n        periodos_disp,\n        format_func=lambda p: month_year_label(p.to_timestamp() if hasattr(p, "to_timestamp") else p),\n    )\n\n    st.divider()\n    st.header("Base")\n    st.download_button(\n        "Baixar modelo Excel",\n        data=build_template(),\n        file_name="modelo_sqdcp_fmds.xlsx",\n        mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",\n    )\n    st.download_button(\n        "Baixar base atual",\n        data=to_workbook_bytes(st.session_state["dados"], st.session_state["acoes"], st.session_state.get("metas", empty_metas())),\n        file_name="base_sqdcp_fmds.xlsx",\n        mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",\n    )\n\n    upload = st.file_uploader("Importar Excel .xlsx", type=["xlsx"])\n    if upload is not None:\n        try:\n            imp_dados, imp_acoes, imp_metas = read_workbook(upload.getvalue())\n            st.session_state["dados"] = imp_dados\n            if not imp_acoes.empty:\n                st.session_state["acoes"] = imp_acoes\n            st.session_state["metas"] = imp_metas\n            erro = save_base(st.session_state["dados"], st.session_state["acoes"], st.session_state.get("metas", empty_metas()))\n            if erro:\n                st.warning(erro)\n            else:\n                st.success("Base importada e salva.")\n            st.rerun()\n        except Exception as exc:\n            st.error(f"Erro ao importar arquivo: {exc}")\n\n    st.divider()\n    confirmar = st.checkbox("Confirmo que desejo excluir toda a base")\n    if st.button("Excluir base de dados", disabled=not confirmar, type="secondary"):\n        st.session_state["dados"] = empty_dados()\n        st.session_state["acoes"] = empty_acoes()\n        st.session_state["metas"] = empty_metas()\n        erro = save_base(st.session_state["dados"], st.session_state["acoes"], st.session_state.get("metas", empty_metas()))\n        if erro:\n            st.warning(erro)\n        else:\n            st.success("Base excluída e sincronizada.")\n        st.rerun()\n\n# Metas dos indicadores\nwith st.expander("Metas dos indicadores", expanded=False):\n    st.caption("Defina a referência dos relógios. Para acidentes, reclamações e perdas, quanto menor melhor. Para atendimento no prazo e eficiência, quanto maior melhor.")\n    metas_edit = normalize_metas(st.session_state.get("metas", empty_metas()))\n    edited_metas = st.data_editor(\n        metas_edit,\n        num_rows="fixed",\n        use_container_width=True,\n        hide_index=True,\n        column_config={\n            "indicador": st.column_config.SelectboxColumn("Indicador", options=INDICADORES, required=True),\n            "meta": st.column_config.NumberColumn("Meta", min_value=0.0, step=0.1),\n            "unidade": st.column_config.TextColumn("Unidade"),\n            "tipo": st.column_config.SelectboxColumn("Critério", options=["menor_melhor", "maior_melhor"], required=True),\n        },\n        disabled=["indicador", "unidade", "tipo"],\n        key="metas_editor",\n    )\n    if st.button("Salvar metas", type="primary"):\n        st.session_state["metas"] = normalize_metas(edited_metas)\n        erro = save_base(st.session_state["dados"], st.session_state["acoes"], st.session_state["metas"])\n        if erro:\n            st.warning(erro)\n        else:\n            st.success("Metas salvas e sincronizadas no GitHub.")\n        st.rerun()\n\n# Lançamento em massa\nwith st.expander("Lançamento em massa", expanded=False):\n    base_edit = normalize_dados(st.session_state["dados"])\n    if base_edit.empty:\n        base_edit = pd.DataFrame([{\n            "data": pd.to_datetime(date.today()),\n            "acidentes_un": 0,\n            "reclamacoes_un": 0,\n            "perda_prensas_t": 0.0,\n            "perda_litografia_t": 0.0,\n            "perda_montagem_t": 0.0,\n            "atendimento_prazo_pct": 100.0,\n            "eficiencia_prensas_pct": 0.0,\n            "eficiencia_litografia_pct": 0.0,\n            "eficiencia_montagem_pct": 0.0,\n        }])\n    edited = st.data_editor(\n        base_edit,\n        num_rows="dynamic",\n        use_container_width=True,\n        hide_index=True,\n        column_config={\n            "data": st.column_config.DateColumn("Mês/Ano", format="MM/YYYY"),\n            "acidentes_un": st.column_config.NumberColumn("Acidentes", min_value=0, step=1),\n            "reclamacoes_un": st.column_config.NumberColumn("Reclamações", min_value=0, step=1),\n            "perda_prensas_t": st.column_config.NumberColumn("Perda Prensas t", min_value=0.0, step=0.01),\n            "perda_litografia_t": st.column_config.NumberColumn("Perda Litografia t", min_value=0.0, step=0.01),\n            "perda_montagem_t": st.column_config.NumberColumn("Perda Montagem t", min_value=0.0, step=0.01),\n            "atendimento_prazo_pct": st.column_config.NumberColumn("Atendimento %", min_value=0.0, max_value=100.0, step=0.1),\n            "eficiencia_prensas_pct": st.column_config.NumberColumn("Eficiência Prensas %", min_value=0.0, max_value=100.0, step=0.1),\n            "eficiencia_litografia_pct": st.column_config.NumberColumn("Eficiência Litografia %", min_value=0.0, max_value=100.0, step=0.1),\n            "eficiencia_montagem_pct": st.column_config.NumberColumn("Eficiência Montagem %", min_value=0.0, max_value=100.0, step=0.1),\n        },\n    )\n    if st.button("Salvar lançamentos", type="primary"):\n        st.session_state["dados"] = normalize_dados(edited)\n        erro = save_base(st.session_state["dados"], st.session_state["acoes"], st.session_state.get("metas", empty_metas()))\n        if erro:\n            st.warning(erro)\n        else:\n            st.success("Lançamentos salvos e sincronizados no GitHub.")\n        st.rerun()\n\n# Filtro\nfiltro = normalize_dados(st.session_state["dados"])\nif not filtro.empty:\n    filtro = filtro[filtro["data"].dt.to_period("M") == periodo_sel]\n\nif filtro.empty:\n    st.warning("Nenhum dado encontrado para o filtro selecionado.")\nelse:\n    metas = normalize_metas(st.session_state.get("metas", empty_metas()))\n    acidentes = filtro["acidentes_un"].sum()\n    reclamacoes = filtro["reclamacoes_un"].sum()\n    perda = filtro[["perda_prensas_t", "perda_litografia_t", "perda_montagem_t"]].sum().sum()\n    atendimento = filtro["atendimento_prazo_pct"].mean()\n    eficiencia = filtro[["eficiencia_prensas_pct", "eficiencia_litografia_pct", "eficiencia_montagem_pct"]].mean(axis=1).mean()\n\n    meta_acidentes = get_meta(metas, "Acidentes", 0.0)\n    meta_reclamacoes = get_meta(metas, "Reclamações", 0.0)\n    meta_perda = get_meta(metas, "Perda", 0.0)\n    meta_atendimento = get_meta(metas, "Atendimento no prazo", 100.0)\n    meta_eficiencia = get_meta(metas, "Eficiência", 100.0)\n\n    c1, c2, c3, c4, c5 = st.columns(5)\n    max_acidentes = max(5, float(acidentes) * 1.5, meta_acidentes * 1.5)\n    max_reclamacoes = max(10, float(reclamacoes) * 1.5, meta_reclamacoes * 1.5)\n    max_perda = max(5, float(perda) * 1.5, meta_perda * 1.5)\n    with c1:\n        st.plotly_chart(gauge("Acidentes", acidentes, "un", 0, max_acidentes, meta_acidentes, "menor_melhor"), use_container_width=True)\n        st.caption(f"Meta: {meta_acidentes:g} un")\n    with c2:\n        st.plotly_chart(gauge("Reclamações", reclamacoes, "un", 0, max_reclamacoes, meta_reclamacoes, "menor_melhor"), use_container_width=True)\n        st.caption(f"Meta: {meta_reclamacoes:g} un")\n    with c3:\n        st.plotly_chart(gauge("Perda", perda, "t", 0, max_perda, meta_perda, "menor_melhor"), use_container_width=True)\n        st.caption(f"Meta: {meta_perda:g} t")\n    with c4:\n        st.plotly_chart(gauge("Atendimento", atendimento, "%", 0, 100, meta_atendimento, "maior_melhor"), use_container_width=True)\n        st.caption(f"Meta: {meta_atendimento:g}%")\n    with c5:\n        st.plotly_chart(gauge("Eficiência", eficiencia, "%", 0, 100, meta_eficiencia, "maior_melhor"), use_container_width=True)\n        st.caption(f"Meta: {meta_eficiencia:g}%")\n\n\n    st.markdown("### Série histórica dos indicadores")\n    historico = normalize_dados(st.session_state["dados"]).copy()\n    if not historico.empty:\n        historico["mes_periodo"] = historico["data"].dt.to_period("M").astype(str)\n        hist = historico.groupby("mes_periodo", as_index=False).agg(\n            acidentes_un=("acidentes_un", "sum"),\n            reclamacoes_un=("reclamacoes_un", "sum"),\n            perda_prensas_t=("perda_prensas_t", "sum"),\n            perda_litografia_t=("perda_litografia_t", "sum"),\n            perda_montagem_t=("perda_montagem_t", "sum"),\n            atendimento_prazo_pct=("atendimento_prazo_pct", "mean"),\n            eficiencia_prensas_pct=("eficiencia_prensas_pct", "mean"),\n            eficiencia_litografia_pct=("eficiencia_litografia_pct", "mean"),\n            eficiencia_montagem_pct=("eficiencia_montagem_pct", "mean"),\n        )\n        hist["perda_t"] = hist[["perda_prensas_t", "perda_litografia_t", "perda_montagem_t"]].sum(axis=1)\n        hist["eficiencia_pct"] = hist[["eficiencia_prensas_pct", "eficiencia_litografia_pct", "eficiencia_montagem_pct"]].mean(axis=1)\n        hist["mes_rotulo"] = pd.to_datetime(hist["mes_periodo"] + "-01").apply(month_year_label)\n\n        series_config = [\n            ("Acidentes", "acidentes_un", "un", meta_acidentes),\n            ("Reclamações", "reclamacoes_un", "un", meta_reclamacoes),\n            ("Perda", "perda_t", "t", meta_perda),\n            ("Atendimento", "atendimento_prazo_pct", "%", meta_atendimento),\n            ("Eficiência", "eficiencia_pct", "%", meta_eficiencia),\n        ]\n        hcols = st.columns(5)\n        for col, (titulo, campo, unidade, meta_valor) in zip(hcols, series_config):\n            with col:\n                fig_hist = go.Figure()\n                fig_hist.add_trace(go.Scatter(\n                    x=hist["mes_rotulo"],\n                    y=hist[campo],\n                    mode="lines+markers",\n                    name=titulo,\n                ))\n                fig_hist.add_hline(\n                    y=meta_valor,\n                    line_dash="dash",\n                    annotation_text="Meta",\n                    annotation_position="top left",\n                )\n                y_range = auto_y_range(hist[campo], meta_valor, min_floor=0.0)\n                fig_hist.update_layout(\n                    title=f"Histórico — {titulo}",\n                    height=210,\n                    margin=dict(l=5, r=5, t=45, b=45),\n                    xaxis_title="",\n                    yaxis_title=unidade,\n                    showlegend=False,\n                    yaxis=dict(range=y_range, fixedrange=False),\n                    xaxis=dict(tickangle=45),\n                )\n                st.plotly_chart(fig_hist, use_container_width=True)\n    st.subheader("Detalhamento por área")\n    d1, d2 = st.columns(2)\n    with d1:\n        perdas_area = pd.DataFrame({\n            "Área": ["Prensas", "Litografia", "Montagem"],\n            "Perda t": [\n                filtro["perda_prensas_t"].sum(),\n                filtro["perda_litografia_t"].sum(),\n                filtro["perda_montagem_t"].sum(),\n            ],\n        })\n        fig_perdas = go.Figure(go.Bar(\n            x=perdas_area["Área"],\n            y=perdas_area["Perda t"],\n            text=perdas_area["Perda t"].round(2),\n            textposition="outside",\n        ))\n        fig_perdas.update_layout(\n            title="Perdas por área — toneladas",\n            xaxis_title="Área",\n            yaxis_title="Perda (t)",\n            yaxis=dict(range=[0, max(0.01, float(perdas_area["Perda t"].max()) * 1.25)]),\n            height=360,\n            margin=dict(l=10, r=10, t=60, b=10),\n        )\n        st.plotly_chart(fig_perdas, use_container_width=True)\n    with d2:\n        efic_area = pd.DataFrame({\n            "Área": ["Prensas", "Litografia", "Montagem"],\n            "Eficiência %": [\n                filtro["eficiencia_prensas_pct"].mean(),\n                filtro["eficiencia_litografia_pct"].mean(),\n                filtro["eficiencia_montagem_pct"].mean(),\n            ],\n        }).fillna(0)\n        fig_efic = go.Figure(go.Bar(\n            x=efic_area["Área"],\n            y=efic_area["Eficiência %"],\n            text=efic_area["Eficiência %"].round(1).astype(str) + "%",\n            textposition="outside",\n        ))\n        fig_efic.update_layout(\n            title="Eficiência por área — percentual",\n            xaxis_title="Área",\n            yaxis_title="Eficiência (%)",\n            yaxis=dict(range=[0, 100]),\n            height=360,\n            margin=dict(l=10, r=10, t=60, b=10),\n        )\n        st.plotly_chart(fig_efic, use_container_width=True)\n\nst.divider()\nst.subheader("Ações por indicador")\nst.caption("Em cada aba, a ação é gravada automaticamente no indicador correspondente. Use a sinaleira em branco quando não houver ação aberta.")\nacoes_edit = normalize_acoes(st.session_state["acoes"])\nfor indicador in INDICADORES:\n    with st.expander(f"Ações - {indicador}", expanded=True):\n        subset = acoes_edit[acoes_edit["indicador"] == indicador].copy()\n        if subset.empty:\n            subset = pd.DataFrame([{\n                "descricao": "",\n                "responsavel": "",\n                "prazo": pd.NaT,\n                "status": "",\n            }])\n        subset["sinaleira"] = subset["status"].apply(status_sinaleira)\n        subset = subset[["sinaleira", "descricao", "responsavel", "prazo"]]\n        edited_acoes = st.data_editor(\n            subset,\n            num_rows="dynamic",\n            hide_index=True,\n            use_container_width=True,\n            key=f"acoes_{indicador}",\n            column_config={\n                "sinaleira": st.column_config.SelectboxColumn(\n                    "Sinaleira",\n                    options=["", "🔴 Aberta", "🟡 Em andamento", "🟢 Concluída"],\n                    help="Deixe em branco quando não houver ação aberta.",\n                    required=False,\n                ),\n                "descricao": st.column_config.TextColumn("Descrição"),\n                "responsavel": st.column_config.TextColumn("Responsável"),\n                "prazo": st.column_config.DateColumn("Prazo", format="DD/MM/YYYY"),\n            },\n        )\n        if st.button(f"Salvar ações - {indicador}", key=f"salvar_{indicador}"):\n            outras = acoes_edit[acoes_edit["indicador"] != indicador]\n            novas = edited_acoes.copy()\n            novas["indicador"] = indicador\n            novas["status"] = novas["sinaleira"].apply(sinaleira_to_status)\n            novas = novas[["indicador", "descricao", "responsavel", "prazo", "status"]]\n            novas = normalize_acoes(novas)\n            novas = novas[(novas["descricao"].str.strip() != "") | (novas["responsavel"].str.strip() != "") | (novas["status"].str.strip() != "")]\n            st.session_state["acoes"] = normalize_acoes(pd.concat([outras, novas], ignore_index=True))\n            erro = save_base(st.session_state["dados"], st.session_state["acoes"], st.session_state.get("metas", empty_metas()))\n            if erro:\n                st.warning(erro)\n            else:\n                st.success("Ações salvas e sincronizadas no GitHub.")\n            st.rerun()\n',
    'cpk.py': 'import io\nimport json\nimport math\nimport os\nimport re\nfrom datetime import datetime, date\n\nimport pandas as pd\nimport streamlit as st\nimport plotly.graph_objects as go\n\ntry:\n    from reportlab.lib.pagesizes import A4\n    from reportlab.lib import colors\n    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle\n    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle\n    from reportlab.lib.units import mm\n    from reportlab.graphics.shapes import Drawing, Line, Circle, String, Rect\nexcept Exception:\n    A4 = None\n\nst.set_page_config(page_title="Carta de Inspeção CPK", layout="wide", page_icon="📊")\n\nBASE_DIR = os.path.abspath("data/cpk")\nos.makedirs(BASE_DIR, exist_ok=True)\nDATA_CPK_DIR = os.path.join(os.getcwd(), "data", "cpk")\nos.makedirs(DATA_CPK_DIR, exist_ok=True)\nMODELOS_FILE = os.path.join(DATA_CPK_DIR, "modelos_cartas_cpk.json")\n\nst.markdown(\n    """\n    <style>\n    .stApp {background: linear-gradient(180deg,#0a0a0d 0%,#12121a 100%); color:#e8e8f0;}\n    h1, h2, h3 {color:#e8e8f0;}\n    .version {color:#8a8a9e; font-size:10px; font-style:italic; text-align:right;}\n    .card {background:#1c1c25; border:1px solid #2a2a32; border-radius:16px; padding:16px; margin-bottom:10px;}\n    .ok {border-left:5px solid #00e5a0; padding:10px; background:#11181a; border-radius:10px; margin-bottom:8px;}\n    .wn {border-left:5px solid #ffb340; padding:10px; background:#1d1810; border-radius:10px; margin-bottom:8px;}\n    .fl {border-left:5px solid #ff4d4d; padding:10px; background:#1d1111; border-radius:10px; margin-bottom:8px;}\n    .muted {color:#9a9aad; font-size:0.9rem;}\n    .orange-help {border-left:5px solid #ff8c00; padding:10px; background:#20160a; border-radius:10px; margin-bottom:8px;}\n    div.stButton > button[kind="primary"] {background:#00a86b !important; border-color:#00a86b !important; color:white !important;}\n    div.stFormSubmitButton > button {background:#ff8c00 !important; border-color:#ff8c00 !important; color:white !important; font-weight:700;}\n    div.stDownloadButton > button {background:#00a86b !important; border-color:#00a86b !important; color:white !important; font-weight:700;}\n    </style>\n    """,\n    unsafe_allow_html=True,\n)\n\nVERSION = f"RM_{datetime.now().strftime(\'%d_%m_%Y_%H%M\')}"\nst.markdown(f"<div class=\'version\'>{VERSION}</div>", unsafe_allow_html=True)\n\n# ─────────────────────────────────────────────────────────────────────────────\n# Persistência dos modelos\n# ─────────────────────────────────────────────────────────────────────────────\ndef load_modelos():\n    if not os.path.exists(MODELOS_FILE):\n        return {}\n    try:\n        with open(MODELOS_FILE, "r", encoding="utf-8") as f:\n            data = json.load(f)\n        return data if isinstance(data, dict) else {}\n    except Exception:\n        return {}\n\n\ndef save_modelos(modelos):\n    with open(MODELOS_FILE, "w", encoding="utf-8") as f:\n        json.dump(modelos, f, ensure_ascii=False, indent=2)\n\n\ndef modelo_from_state(nome):\n    return {\n        "nome": nome,\n        "criado_em": datetime.now().strftime("%d/%m/%Y %H:%M"),\n        "carta_base": {\n            "linha": st.session_state.carta_dados.get("linha", ""),\n            "embalagem": st.session_state.carta_dados.get("embalagem", ""),\n            "domo_mat": st.session_state.carta_dados.get("domo_mat", ""),\n            "esp_domo": st.session_state.carta_dados.get("esp_domo", ""),\n            "corpo_mat": st.session_state.carta_dados.get("corpo_mat", ""),\n            "esp_corpo": st.session_state.carta_dados.get("esp_corpo", ""),\n            "fundo_mat": st.session_state.carta_dados.get("fundo_mat", ""),\n            "esp_fundo": st.session_state.carta_dados.get("esp_fundo", ""),\n        },\n        "caracteristicas": [\n            {\n                "descricao": c["descricao"],\n                "lie": c["lie"],\n                "lse": c["lse"],\n                "num_amostras": c["num_amostras"],\n                "num_medicoes": c.get("num_medicoes", 3),\n            }\n            for c in st.session_state.caracteristicas\n        ],\n    }\n\n\ndef aplicar_modelo(modelo):\n    base = modelo.get("carta_base", {})\n    st.session_state.carta_dados = {\n        **st.session_state.get("carta_dados", {}),\n        "linha": base.get("linha", ""),\n        "embalagem": base.get("embalagem", ""),\n        "domo_mat": base.get("domo_mat", ""),\n        "esp_domo": base.get("esp_domo", ""),\n        "corpo_mat": base.get("corpo_mat", ""),\n        "esp_corpo": base.get("esp_corpo", ""),\n        "fundo_mat": base.get("fundo_mat", ""),\n        "esp_fundo": base.get("esp_fundo", ""),\n    }\n    chars = []\n    for idx, c in enumerate(modelo.get("caracteristicas", []), start=1):\n        n = int(c.get("num_amostras", 1) or 1)\n        m = int(c.get("num_medicoes", 3) or 3)\n        chars.append({\n            "id": f"C{idx:03d}_{datetime.now().strftime(\'%H%M%S\')}",\n            "descricao": c.get("descricao", ""),\n            "lie": float(c.get("lie")),\n            "lse": float(c.get("lse")),\n            "num_amostras": n,\n            "num_medicoes": m,\n            "medicoes": [{"Amostra": i, **{f"Medida {j}": None for j in range(1, m + 1)}} for i in range(1, n + 1)],\n        })\n    st.session_state.caracteristicas = chars\n    st.session_state.selected_id = chars[0]["id"] if chars else None\n\n# ─────────────────────────────────────────────────────────────────────────────\n# Estado\n# ─────────────────────────────────────────────────────────────────────────────\ndef init_state():\n    defaults = {\n        "carta_ok": False,\n        "caracteristicas": [],\n        "selected_id": None,\n        "carta_dados": {},\n        "modelos": load_modelos(),\n        "char_form_nonce": 0,\n    }\n    for k, v in defaults.items():\n        if k not in st.session_state:\n            st.session_state[k] = v\n\ninit_state()\n\n# ─────────────────────────────────────────────────────────────────────────────\n# Cálculo estatístico\n# ─────────────────────────────────────────────────────────────────────────────\ndef parse_float(value):\n    if value is None or value == "":\n        return None\n    try:\n        if pd.isna(value):\n            return None\n    except Exception:\n        pass\n    try:\n        return float(str(value).replace(",", "."))\n    except Exception:\n        return None\n\n\ndef calc_stats(samples, lse=None, lie=None):\n    vals = [float(v) for v in samples if v is not None]\n    if len(vals) < 2:\n        return None\n    n = len(vals)\n    mean = sum(vals) / n\n    variance = sum((v - mean) ** 2 for v in vals) / (n - 1)\n    std = math.sqrt(variance)\n    if std == 0:\n        return None\n    cp = cpu = cpl = cpk = None\n    if lse is not None and lie is not None:\n        cp = (lse - lie) / (6 * std)\n        cpu = (lse - mean) / (3 * std)\n        cpl = (mean - lie) / (3 * std)\n        cpk = min(cpu, cpl)\n    elif lse is not None:\n        cpu = (lse - mean) / (3 * std)\n        cpk = cpu\n    elif lie is not None:\n        cpl = (mean - lie) / (3 * std)\n        cpk = cpl\n    return {"vals": vals, "n": n, "mean": mean, "std": std, "cp": cp, "cpu": cpu, "cpl": cpl, "cpk": cpk}\n\n\ndef classify_cpk(cpk):\n    if cpk is None:\n        return "Sem cálculo"\n    if cpk >= 1.33:\n        return "Capaz"\n    if cpk >= 1.00:\n        return "Marginal"\n    return "Incapaz"\n\n\ndef measurement_keys(char):\n    qtd = int(char.get("num_medicoes", 3) or 3)\n    return [f"Medida {i}" for i in range(1, qtd + 1)]\n\n\ndef flatten_measurements(char):\n    vals = []\n    keys = measurement_keys(char)\n    for row in char.get("medicoes", []):\n        for key in keys:\n            v = parse_float(row.get(key))\n            if v is not None:\n                vals.append(v)\n    return vals\n\n\ndef amostras_completas(char):\n    completas = 0\n    keys = measurement_keys(char)\n    for row in char.get("medicoes", []):\n        if all(parse_float(row.get(k)) is not None for k in keys):\n            completas += 1\n    return completas\n\n\ndef calc_characteristic(char):\n    vals = flatten_measurements(char)\n    s = calc_stats(vals, char.get("lse"), char.get("lie"))\n    result = {\n        "id": char["id"],\n        "descricao": char["descricao"],\n        "lie": char.get("lie"),\n        "lse": char.get("lse"),\n        "amostras_previstas": char.get("num_amostras", 0),\n        "amostras_completas": amostras_completas(char),\n        "medicoes_por_amostra": int(char.get("num_medicoes", 3) or 3),\n        "medidas_previstas": char.get("num_amostras", 0) * int(char.get("num_medicoes", 3) or 3),\n        "medidas_realizadas": len(vals),\n        "valores": vals,\n        "n": s["n"] if s else 0,\n        "media": round(s["mean"], 4) if s else None,\n        "desvio": round(s["std"], 4) if s else None,\n        "cp": round(s["cp"], 4) if s and s["cp"] is not None else None,\n        "cpu": round(s["cpu"], 4) if s and s["cpu"] is not None else None,\n        "cpl": round(s["cpl"], 4) if s and s["cpl"] is not None else None,\n        "cpk": round(s["cpk"], 4) if s and s["cpk"] is not None else None,\n    }\n    result["status"] = classify_cpk(result["cpk"])\n    return result\n\n\ndef characteristic_has_measurements(char):\n    return len(flatten_measurements(char)) > 0\n\ndef descricao_normalizada(txt):\n    return re.sub(r"\\s+", " ", str(txt or "").strip()).casefold()\n\ndef build_insights(results):\n    valid = [r for r in results if r.get("cpk") is not None]\n    if not valid:\n        return [{"level":"wn", "text":"Ainda não há medições suficientes para análise. Cada característica deve ter medições válidas e limites de especificação informados."}]\n    fail = [r for r in valid if r["cpk"] < 1]\n    warn = [r for r in valid if 1 <= r["cpk"] < 1.33]\n    ok = [r for r in valid if r["cpk"] >= 1.33]\n    insights = []\n    if fail:\n        names = ", ".join(f"{r[\'descricao\']} (Cpk {r[\'cpk\']:.2f})" for r in fail)\n        insights.append({"level":"fl", "text":f"Parecer: processo não capaz para {len(fail)} característica(s): {names}. Minha recomendação é não liberar o lote sem avaliação técnica, revisar setup, segregar material suspeito e repetir a coleta após correção."})\n    if warn:\n        names = ", ".join(f"{r[\'descricao\']} (Cpk {r[\'cpk\']:.2f})" for r in warn)\n        insights.append({"level":"wn", "text":f"Parecer: processo marginal para {len(warn)} característica(s): {names}. Eu manteria o processo em acompanhamento reforçado, com ajuste preventivo e aumento temporário da frequência de inspeção."})\n    if ok and not fail and not warn:\n        insights.append({"level":"ok", "text":f"Parecer: processo capaz. Todas as {len(ok)} característica(s) avaliadas apresentam Cpk ≥ 1,33, indicando boa condição estatística frente aos limites especificados."})\n    for r in valid:\n        cp, cpk = r.get("cp"), r.get("cpk")\n        if cp and cpk and cp > 0 and (cp - cpk) / cp > 0.15:\n            perda = round((cp - cpk) / cp * 100)\n            insights.append({"level":"wn", "text":f"Descentramento identificado em {r[\'descricao\']}: Cp={cp:.2f} e Cpk={cpk:.2f}, com perda aproximada de {perda}% da capacidade potencial. A variação pode estar aceitável, mas o processo está deslocado em relação ao centro da especificação."})\n    incompletas = [r for r in results if r["amostras_completas"] < r["amostras_previstas"]]\n    if incompletas:\n        names = ", ".join(f"{r[\'descricao\']} ({r[\'amostras_completas\']}/{r[\'amostras_previstas\']} amostras)" for r in incompletas)\n        insights.append({"level":"wn", "text":f"Atenção: existem coletas incompletas em {names}. O parecer estatístico é parcial até completar todas as medições previstas em cada amostra."})\n    pct_ok = round(len(ok) / len(valid) * 100)\n    level = "ok" if pct_ok >= 80 and not fail else "wn" if pct_ok >= 50 else "fl"\n    insights.append({"level":level, "text":f"Resumo geral: {pct_ok}% das características calculadas estão capazes. Total analisado: {len(valid)} característica(s)."})\n    return insights\n\n\ndef control_chart(result):\n    vals = result.get("valores", [])\n    if len(vals) < 2:\n        return None\n    mean = sum(vals) / len(vals)\n    std = math.sqrt(sum((v - mean) ** 2 for v in vals) / (len(vals) - 1))\n    ucl = mean + 3 * std\n    lcl = mean - 3 * std\n    x = list(range(1, len(vals) + 1))\n    fig = go.Figure()\n    fig.add_trace(go.Scatter(\n        x=x,\n        y=vals,\n        mode="lines+markers",\n        name="Medições",\n        line=dict(width=2),\n        marker=dict(size=7),\n    ))\n    # A média aparece no título para não poluir o gráfico com mais uma linha.\n    fig.add_hline(y=ucl, line_dash="dash", line_color="#ff4d4d", line_width=3, annotation_text="LSC", annotation_font_color="#ff4d4d")\n    fig.add_hline(y=lcl, line_dash="dash", line_color="#ff4d4d", line_width=3, annotation_text="LIC", annotation_font_color="#ff4d4d")\n    if result.get("lse") is not None:\n        fig.add_hline(y=result["lse"], line_dash="solid", line_color="#ff4d4d", line_width=4, annotation_text="LSE", annotation_font_color="#ff4d4d")\n    if result.get("lie") is not None:\n        fig.add_hline(y=result["lie"], line_dash="solid", line_color="#ff4d4d", line_width=4, annotation_text="LIE", annotation_font_color="#ff4d4d")\n    media_txt = "—" if result.get("media") is None else f"{result[\'media\']:.4f}"\n    cpk_txt = "—" if result.get("cpk") is None else f"{result[\'cpk\']:.4f}"\n    fig.update_layout(\n        height=370,\n        title=f"{result[\'descricao\']} | Cpk: {cpk_txt} | Média: {media_txt}",\n        paper_bgcolor="#1c1c25",\n        plot_bgcolor="#16161d",\n        font=dict(color="#e8e8f0"),\n        margin=dict(l=20, r=20, t=55, b=20),\n        xaxis_title="Sequência das medições",\n        yaxis_title="Valor medido",\n        showlegend=False,\n    )\n    return fig\n\n\ndef pdf_chart_drawing(result, W):\n    vals = result.get("valores", [])\n    if len(vals) < 2:\n        return None\n    mean = sum(vals) / len(vals)\n    std = math.sqrt(sum((v - mean) ** 2 for v in vals) / (len(vals) - 1))\n    ucl = mean + 3 * std\n    lcl = mean - 3 * std\n    lse = result.get("lse")\n    lie = result.get("lie")\n    all_v = vals + [ucl, lcl] + ([lse] if lse is not None else []) + ([lie] if lie is not None else [])\n    vmn, vmx = min(all_v), max(all_v)\n    vr = vmx - vmn or 0.001\n    DW, DH = W, 42 * mm\n    PAD_L, PAD_R, PAD_T, PAD_B = 13 * mm, 16 * mm, 5 * mm, 7 * mm\n    CW, CH = DW - PAD_L - PAD_R, DH - PAD_T - PAD_B\n\n    def xp(i):\n        return PAD_L + (i / (len(vals) - 1 or 1)) * CW\n\n    def yp(v):\n        return PAD_B + ((v - vmn) / vr) * CH\n\n    d = Drawing(DW, DH)\n    d.add(Rect(0, 0, DW, DH, fillColor=colors.whitesmoke, strokeColor=colors.lightgrey, strokeWidth=0.5))\n\n    def hline(val, col, label, width=1.0, dash=None):\n        y = yp(val)\n        ln = Line(PAD_L, y, PAD_L + CW, y, strokeColor=col, strokeWidth=width)\n        if dash:\n            ln.strokeDashArray = dash\n        d.add(ln)\n        d.add(String(PAD_L + CW + 2, y - 2, label, fontSize=5.5, fillColor=col))\n\n    red = colors.HexColor("#cc0000")\n    hline(ucl, red, "LSC", width=1.4, dash=[2, 2])\n    hline(lcl, red, "LIC", width=1.4, dash=[2, 2])\n    if lse is not None:\n        hline(lse, red, "LSE", width=2.2)\n    if lie is not None:\n        hline(lie, red, "LIE", width=2.2)\n\n    for i in range(len(vals) - 1):\n        d.add(Line(xp(i), yp(vals[i]), xp(i + 1), yp(vals[i + 1]), strokeColor=colors.HexColor("#111111"), strokeWidth=0.9))\n    for i, v in enumerate(vals):\n        out = (lse is not None and v > lse) or (lie is not None and v < lie)\n        col = colors.red if out else colors.HexColor("#00a86b")\n        d.add(Circle(xp(i), yp(v), 1.7, fillColor=col, strokeColor=col))\n    cpk_txt = "—" if result.get("cpk") is None else f"{result[\'cpk\']:.4f}"\n    media_txt = "—" if result.get("media") is None else f"{result[\'media\']:.4f}"\n    d.add(String(PAD_L, DH - 11, f"{result[\'descricao\']} | Cpk: {cpk_txt} | Média: {media_txt}", fontSize=7.5, fillColor=colors.black))\n    return d\n\n\ndef make_pdf(carta, results):\n    if A4 is None:\n        return None\n    buf = io.BytesIO()\n    doc = SimpleDocTemplate(buf, pagesize=A4, leftMargin=12*mm, rightMargin=12*mm, topMargin=12*mm, bottomMargin=14*mm)\n    W = A4[0] - 24*mm\n    styles = getSampleStyleSheet()\n    def S(name, **kw):\n        return ParagraphStyle(name, parent=styles["Normal"], **kw)\n    TEXT = colors.HexColor("#111111")\n    MUTED = colors.HexColor("#555555")\n    story = []\n    story.append(Paragraph("<b>Relatório de Carta de Inspeção e CPK</b>", S("title", fontSize=15, textColor=TEXT, fontName="Helvetica-Bold")))\n    story.append(Paragraph(f"Gerado: {datetime.now().strftime(\'%d/%m/%Y %H:%M\')}", S("sub", fontSize=8, textColor=MUTED)))\n    story.append(Spacer(1, 4*mm))\n    story.append(Paragraph("<b>Dados dos materiais</b>", S("sec_mat", fontSize=9, textColor=TEXT, fontName="Helvetica-Bold")))\n    dados_materiais = [\n        ["Usina domo", carta.get("domo_mat", ""), "Espessura domo", carta.get("esp_domo", "")],\n        ["Usina corpo", carta.get("corpo_mat", ""), "Espessura corpo", carta.get("esp_corpo", "")],\n        ["Usina fundo", carta.get("fundo_mat", ""), "Espessura fundo", carta.get("esp_fundo", "")],\n    ]\n    t_mat = Table(dados_materiais, colWidths=[W*.18, W*.32, W*.18, W*.32])\n    t_mat.setStyle(TableStyle([("GRID", (0,0),(-1,-1), .25, colors.grey), ("FONTSIZE", (0,0),(-1,-1), 7.5), ("BACKGROUND", (0,0),(-1,-1), colors.whitesmoke)]))\n    story.append(t_mat)\n    story.append(Spacer(1, 3*mm))\n\n    story.append(Paragraph("<b>Dados do lote</b>", S("sec_lote", fontSize=9, textColor=TEXT, fontName="Helvetica-Bold")))\n    dados_lote = [\n        ["Linha", carta.get("linha", ""), "Embalagem", carta.get("embalagem", "")],\n        ["Ordem de produção", carta.get("op", ""), "Quantidade", carta.get("lote_qtd", "")],\n        ["Data", carta.get("data", ""), "Observações", carta.get("obs", "")],\n    ]\n    t_lote = Table(dados_lote, colWidths=[W*.18, W*.32, W*.18, W*.32])\n    t_lote.setStyle(TableStyle([("GRID", (0,0),(-1,-1), .25, colors.grey), ("FONTSIZE", (0,0),(-1,-1), 7.5), ("BACKGROUND", (0,0),(-1,-1), colors.whitesmoke)]))\n    story.append(t_lote)\n    story.append(Spacer(1, 3*mm))\n\n    story.append(Paragraph("<b>Responsável pela inspeção</b>", S("sec_resp", fontSize=9, textColor=TEXT, fontName="Helvetica-Bold")))\n    dados_resp = [["Nome", carta.get("responsavel_nome", ""), "Chapa", carta.get("responsavel_chapa", "")]]\n    t_resp = Table(dados_resp, colWidths=[W*.18, W*.32, W*.18, W*.32])\n    t_resp.setStyle(TableStyle([("GRID", (0,0),(-1,-1), .25, colors.grey), ("FONTSIZE", (0,0),(-1,-1), 7.5), ("BACKGROUND", (0,0),(-1,-1), colors.whitesmoke)]))\n    story.append(t_resp)\n    story.append(Spacer(1, 4*mm))\n    rows = [["Característica", "Amostras", "Med./am.", "N", "Média", "Desvio", "LIE", "LSE", "Cp", "Cpk", "Status"]]\n    for r in results:\n        rows.append([r["descricao"], f"{r[\'amostras_completas\']}/{r[\'amostras_previstas\']}", r.get("medicoes_por_amostra", ""), r["n"], r["media"], r["desvio"], r["lie"], r["lse"], r["cp"], r["cpk"], r["status"]])\n    tb = Table(rows, colWidths=[W*.23, W*.075, W*.065, W*.04, W*.075, W*.075, W*.07, W*.07, W*.055, W*.06, W*.095], repeatRows=1)\n    tb.setStyle(TableStyle([("GRID", (0,0),(-1,-1), .25, colors.grey), ("FONTSIZE", (0,0),(-1,-1), 6.2), ("BACKGROUND", (0,0),(-1,0), colors.lightgrey)]))\n    story.append(tb)\n    story.append(Spacer(1, 5*mm))\n    story.append(Paragraph("<b>Gráficos das coletas</b>", S("sec1", fontSize=10, textColor=TEXT, fontName="Helvetica-Bold")))\n    for r in results:\n        d = pdf_chart_drawing(r, W)\n        if d:\n            story.append(d)\n            story.append(Spacer(1, 3*mm))\n    story.append(Paragraph("<b>Análise e parecer automático</b>", S("sec2", fontSize=10, textColor=TEXT, fontName="Helvetica-Bold")))\n    for ins in build_insights(results):\n        story.append(Paragraph(ins["text"], S("body", fontSize=8, leading=11, textColor=TEXT)))\n        story.append(Spacer(1, 1.2*mm))\n    story.append(Spacer(1, 8*mm))\n    story.append(Paragraph(f"Responsável pela inspeção: {carta.get(\'responsavel_nome\',\'\')} | Chapa: {carta.get(\'responsavel_chapa\',\'\')}", S("resp", fontSize=8, textColor=TEXT)))\n    story.append(Paragraph("Assinatura: _______________________________", S("sig", fontSize=8, textColor=TEXT)))\n    doc.build(story)\n    buf.seek(0)\n    return buf.getvalue()\n\n# ─────────────────────────────────────────────────────────────────────────────\n# Interface\n# ─────────────────────────────────────────────────────────────────────────────\nst.title("📊 Carta de Inspeção CPK")\nst.caption("Fluxo: modelo salvo → carta de dados → características sem duplicidade → medições por amostra → análise somente das cartas preenchidas → parecer automático.")\n\ntab1, tab2, tab3, tab4 = st.tabs(["1. Carta de dados", "2. Criar inspeção", "3. Registrar medições", "4. Análise estatística"])\n\nwith tab1:\n    st.subheader("Carta de dados — materiais e identificação")\n\n    modelos = st.session_state.modelos\n    if modelos:\n        st.markdown("#### Utilizar modelo salvo")\n        nomes_modelos = ["— Novo preenchimento sem modelo —"] + sorted(modelos.keys())\n        modelo_sel = st.selectbox("Modelo de carta", nomes_modelos)\n        c_load, c_del = st.columns(2)\n        if c_load.button("Carregar modelo selecionado", use_container_width=True, type="primary", disabled=(modelo_sel.startswith("—"))):\n            aplicar_modelo(modelos[modelo_sel])\n            st.session_state.carta_ok = False\n            st.success("Modelo carregado. Complete os dados variáveis da carta e salve para liberar a inspeção.")\n            st.rerun()\n        if c_del.button("Excluir modelo selecionado", use_container_width=True, disabled=(modelo_sel.startswith("—"))):\n            modelos.pop(modelo_sel, None)\n            save_modelos(modelos)\n            st.session_state.modelos = modelos\n            st.warning("Modelo excluído.")\n            st.rerun()\n    else:\n        st.markdown("<div class=\'orange-help\'>Nenhum modelo salvo ainda. Após criar as características, salve o modelo para reutilizar nas próximas inspeções.</div>", unsafe_allow_html=True)\n\n    with st.form("form_carta"):\n        st.markdown("#### Materiais")\n        m1, m2 = st.columns(2)\n        with m1:\n            domo_mat = st.text_input("Usina domo", value=st.session_state.carta_dados.get("domo_mat", ""))\n        with m2:\n            esp_domo = st.text_input("Espessura domo *", value=st.session_state.carta_dados.get("esp_domo", ""))\n\n        m3, m4 = st.columns(2)\n        with m3:\n            corpo_mat = st.text_input("Usina corpo", value=st.session_state.carta_dados.get("corpo_mat", ""))\n        with m4:\n            esp_corpo = st.text_input("Espessura corpo *", value=st.session_state.carta_dados.get("esp_corpo", ""))\n\n        m5, m6 = st.columns(2)\n        with m5:\n            fundo_mat = st.text_input("Usina fundo", value=st.session_state.carta_dados.get("fundo_mat", ""))\n        with m6:\n            esp_fundo = st.text_input("Espessura fundo *", value=st.session_state.carta_dados.get("esp_fundo", ""))\n\n        st.markdown("#### Dados do lote")\n        l1, l2 = st.columns(2)\n        with l1:\n            linha = st.text_input("Linha *", value=st.session_state.carta_dados.get("linha", "GL"))\n        with l2:\n            embalagem = st.text_input("Embalagem *", value=st.session_state.carta_dados.get("embalagem", ""))\n\n        l3, l4 = st.columns(2)\n        with l3:\n            op = st.text_input("Ordem de produção *", value=st.session_state.carta_dados.get("op", ""))\n        with l4:\n            lote_qtd = st.number_input("Quantidade / lote produzido *", min_value=0, step=1, value=int(st.session_state.carta_dados.get("lote_qtd", 0) or 0))\n\n        data_carta = st.date_input("Data", value=date.today(), format="DD/MM/YYYY")\n\n        st.markdown("#### Responsável pela inspeção")\n        r1, r2 = st.columns(2)\n        with r1:\n            responsavel_nome = st.text_input("Nome do responsável pela inspeção *", value=st.session_state.carta_dados.get("responsavel_nome", ""))\n        with r2:\n            responsavel_chapa = st.text_input("Chapa do responsável pela inspeção *", value=st.session_state.carta_dados.get("responsavel_chapa", ""))\n\n        obs = st.text_area("Observações gerais", value=st.session_state.carta_dados.get("obs", ""))\n        submitted = st.form_submit_button("Salvar carta e liberar criação da inspeção", use_container_width=True)\n    if submitted:\n        obrig = [linha, embalagem, op, esp_corpo, esp_domo, esp_fundo, responsavel_nome, responsavel_chapa]\n        if any(str(v).strip() == "" for v in obrig) or lote_qtd <= 0:\n            st.error("Preencha todos os campos obrigatórios marcados com * e informe lote produzido maior que zero.")\n        else:\n            st.session_state.carta_ok = True\n            st.session_state.carta_dados = {\n                "linha": linha, "embalagem": embalagem, "op": op, "esp_corpo": esp_corpo,\n                "esp_domo": esp_domo, "esp_fundo": esp_fundo, "lote_qtd": lote_qtd,\n                "data": data_carta.strftime("%d/%m/%Y"), "domo_mat": domo_mat,\n                "corpo_mat": corpo_mat, "fundo_mat": fundo_mat, "obs": obs,\n                "responsavel_nome": responsavel_nome.strip(), "responsavel_chapa": responsavel_chapa.strip(),\n            }\n            st.success("Carta salva. A aba \'Criar inspeção\' está liberada.")\n\n    if st.session_state.carta_ok:\n        st.markdown("<div class=\'card\'><b>Carta ativa:</b> " + f"Linha {st.session_state.carta_dados.get(\'linha\')} | Embalagem {st.session_state.carta_dados.get(\'embalagem\')} | OP {st.session_state.carta_dados.get(\'op\')} | Responsável {st.session_state.carta_dados.get(\'responsavel_nome\')} - Chapa {st.session_state.carta_dados.get(\'responsavel_chapa\')}" + "</div>", unsafe_allow_html=True)\n\nwith tab2:\n    st.subheader("Criação das características de inspeção")\n    if not st.session_state.carta_ok:\n        st.warning("Primeiro salve a Carta de dados na aba 1.")\n    else:\n        st.markdown("<div class=\'orange-help\'>O botão de criação fica em laranja para indicar inclusão/edição. Após a característica estar criada e disponível para uso, os botões de abertura e exportação aparecem em verde.</div>", unsafe_allow_html=True)\n        nonce = st.session_state.char_form_nonce\n        with st.form(f"form_caracteristica_{nonce}"):\n            descricao = st.text_input("Descrição da característica *", placeholder="Ex.: Diâmetro interno, pestana, altura, profundidade de expansão", key=f"desc_char_{nonce}")\n            c1, c2 = st.columns(2)\n            with c1:\n                lie = st.text_input("Limite mínimo / LIE *", placeholder="Ex.: 52,10", key=f"lie_char_{nonce}")\n            with c2:\n                lse = st.text_input("Limite máximo / LSE *", placeholder="Ex.: 52,30", key=f"lse_char_{nonce}")\n            c3, c4 = st.columns(2)\n            with c3:\n                num_amostras = st.number_input("Número de amostras que serão coletadas *", min_value=1, max_value=200, step=1, value=10, key=f"n_amostras_char_{nonce}")\n            with c4:\n                num_medicoes = st.number_input("Número de medições por amostra *", min_value=1, max_value=10, step=1, value=3, key=f"n_medicoes_char_{nonce}")\n            submitted_char = st.form_submit_button("Salvar característica", use_container_width=True)\n        if submitted_char:\n            lie_v = parse_float(lie)\n            lse_v = parse_float(lse)\n            desc_norm = descricao_normalizada(descricao)\n            duplicada = any(descricao_normalizada(c.get("descricao")) == desc_norm for c in st.session_state.caracteristicas)\n            if not descricao.strip() or lie_v is None or lse_v is None or lie_v >= lse_v:\n                st.error("Informe descrição, limite mínimo e limite máximo válidos. O limite mínimo deve ser menor que o limite máximo.")\n            elif duplicada:\n                st.error(f"A característica \'{descricao.strip()}\' já possui uma carta de inspeção criada. Não é permitido salvar duas cartas com a mesma descrição.")\n            else:\n                new_id = f"C{len(st.session_state.caracteristicas)+1:03d}_{datetime.now().strftime(\'%H%M%S\')}"\n                medicoes = [{"Amostra": i, **{f"Medida {j}": None for j in range(1, int(num_medicoes) + 1)}} for i in range(1, int(num_amostras)+1)]\n                st.session_state.caracteristicas.append({\n                    "id": new_id, "descricao": descricao.strip(), "lie": lie_v, "lse": lse_v,\n                    "num_amostras": int(num_amostras), "num_medicoes": int(num_medicoes), "medicoes": medicoes,\n                })\n                st.session_state.selected_id = new_id\n                st.session_state.char_form_nonce += 1\n                st.success("Característica criada e habilitada para utilização. Os campos foram limpos para nova inclusão.")\n                st.rerun()\n\n        if st.session_state.caracteristicas:\n            st.markdown("#### Características abertas")\n            for char in st.session_state.caracteristicas:\n                result = calc_characteristic(char)\n                cols = st.columns([4, 1, 1, 1])\n                cols[0].markdown(f"**{char[\'descricao\']}**  \\nLIE: {char[\'lie\']} | LSE: {char[\'lse\']} | Amostras: {char[\'num_amostras\']} | Medições/amostra: {char.get(\'num_medicoes\', 3)} | Medições: {result[\'medidas_realizadas\']}/{result[\'medidas_previstas\']}")\n                cols[1].metric("Cpk", "—" if result["cpk"] is None else result["cpk"])\n                cols[2].markdown(f"**Status:** {result[\'status\']}")\n                if cols[3].button("Abrir", key=f"open_{char[\'id\']}", type="primary"):\n                    st.session_state.selected_id = char["id"]\n                    st.success(f"Característica selecionada: {char[\'descricao\']}")\n\n            st.markdown("#### Salvar modelo da carta")\n            nome_modelo = st.text_input("Nome do modelo para reutilização", value=f"{st.session_state.carta_dados.get(\'linha\',\'\')}_{st.session_state.carta_dados.get(\'embalagem\',\'\')}".strip("_"))\n            if st.button("Salvar modelo com estas características", use_container_width=True, type="primary"):\n                if not nome_modelo.strip():\n                    st.error("Informe um nome para o modelo.")\n                else:\n                    st.session_state.modelos[nome_modelo.strip()] = modelo_from_state(nome_modelo.strip())\n                    save_modelos(st.session_state.modelos)\n                    st.success("Modelo salvo. Ele será carregado automaticamente como opção quando o aplicativo for reiniciado.")\n\nwith tab3:\n    st.subheader("Registro das medições")\n    if not st.session_state.caracteristicas:\n        st.warning("Crie pelo menos uma característica na aba 2 ou carregue um modelo salvo.")\n    else:\n        options = {f"{c[\'descricao\']} | {c[\'id\']}": c["id"] for c in st.session_state.caracteristicas}\n        current_key = next((k for k, v in options.items() if v == st.session_state.selected_id), list(options.keys())[0])\n        selected_label = st.selectbox("Selecione a característica", list(options.keys()), index=list(options.keys()).index(current_key))\n        st.session_state.selected_id = options[selected_label]\n        char = next(c for c in st.session_state.caracteristicas if c["id"] == st.session_state.selected_id)\n        keys_medicao = measurement_keys(char)\n        st.info(f"Cada amostra deve conter obrigatoriamente {char.get(\'num_medicoes\', 3)} medição(ões). Característica: {char[\'descricao\']} | LIE {char[\'lie\']} | LSE {char[\'lse\']}")\n        df_med = pd.DataFrame(char["medicoes"])\n        expected_cols = ["Amostra"] + keys_medicao\n        for col in expected_cols:\n            if col not in df_med.columns:\n                df_med[col] = None\n        df_med = df_med[expected_cols]\n        column_config = {"Amostra": st.column_config.NumberColumn("Amostra", disabled=True)}\n        column_config.update({k: st.column_config.NumberColumn(k, format="%.4f") for k in keys_medicao})\n        edited_med = st.data_editor(\n            df_med,\n            use_container_width=True,\n            hide_index=True,\n            num_rows="fixed",\n            column_config=column_config,\n            key=f"editor_{char[\'id\']}",\n        )\n        if st.button("Salvar medições desta característica", use_container_width=True, type="primary"):\n            registros = edited_med.to_dict("records")\n            incompletas = []\n            for row in registros:\n                vals = [parse_float(row.get(k)) for k in keys_medicao]\n                if any(v is not None for v in vals) and not all(v is not None for v in vals):\n                    incompletas.append(int(row.get("Amostra", 0)))\n            if incompletas:\n                st.error(f"As amostras {incompletas} estão parcialmente preenchidas. Cada amostra registrada deve ter {len(keys_medicao)} medição(ões).")\n            else:\n                char["medicoes"] = registros\n                st.success("Medições salvas. A análise estatística já pode ser consultada na aba 4.")\n\nwith tab4:\n    st.subheader("Análise estatística e parecer do processo")\n    if not st.session_state.caracteristicas:\n        st.warning("Não há características criadas para análise.")\n    else:\n        todas_results = [calc_characteristic(c) for c in st.session_state.caracteristicas]\n        chars_preenchidas = [c for c in st.session_state.caracteristicas if characteristic_has_measurements(c)]\n        results = [calc_characteristic(c) for c in chars_preenchidas]\n        if not results:\n            st.warning("Nenhuma carta preenchida foi localizada. A análise estatística considera somente características com medições registradas.")\n            st.stop()\n        valid = [r for r in results if r.get("cpk") is not None]\n        ok_n = len([r for r in valid if r["cpk"] >= 1.33])\n        wn_n = len([r for r in valid if 1 <= r["cpk"] < 1.33])\n        fl_n = len([r for r in valid if r["cpk"] < 1])\n        avg_cpk = round(sum(r["cpk"] for r in valid) / len(valid), 2) if valid else None\n        c1, c2, c3, c4, c5 = st.columns(5)\n        c1.metric("Cpk médio", "—" if avg_cpk is None else avg_cpk)\n        c2.metric("Capazes ≥ 1,33", ok_n)\n        c3.metric("Marginais", wn_n)\n        c4.metric("Incapazes", fl_n)\n        c5.metric("Cartas preenchidas", len(results))\n        cartas_branco = len(todas_results) - len(results)\n        if cartas_branco > 0:\n            st.info(f"{cartas_branco} carta(s) em branco foram desconsideradas da análise estatística.")\n\n        result_df = pd.DataFrame([{\n            "Característica": r["descricao"], "Amostras completas": f"{r[\'amostras_completas\']}/{r[\'amostras_previstas\']}",\n            "Medições/amostra": r.get("medicoes_por_amostra"), "Medições realizadas": r["medidas_realizadas"], "N": r["n"], "Média": r["media"],\n            "Desvio": r["desvio"], "LIE": r["lie"], "LSE": r["lse"], "Cp": r["cp"],\n            "CPU": r["cpu"], "CPL": r["cpl"], "Cpk": r["cpk"], "Status": r["status"],\n        } for r in results])\n        st.dataframe(result_df, use_container_width=True, hide_index=True)\n\n        st.markdown("#### Gráficos das coletas por característica")\n        for r in results:\n            fig = control_chart(r)\n            if fig:\n                st.plotly_chart(fig, use_container_width=True)\n\n        st.markdown("#### Análise e parecer automático")\n        for ins in build_insights(results):\n            st.markdown(f"<div class=\'{ins[\'level\']}\'>{ins[\'text\']}</div>", unsafe_allow_html=True)\n\n        st.markdown("#### Exportação")\n        col_a, col_b = st.columns(2)\n        with col_a:\n            xlsx = io.BytesIO()\n            with pd.ExcelWriter(xlsx, engine="openpyxl") as writer:\n                pd.DataFrame([st.session_state.carta_dados]).to_excel(writer, sheet_name="CARTA", index=False)\n                result_df.to_excel(writer, sheet_name="RESULTADOS", index=False)\n                for c in chars_preenchidas:\n                    safe = re.sub(r"[^A-Za-z0-9_]+", "_", c["descricao"][:20]) or c["id"]\n                    pd.DataFrame(c["medicoes"]).to_excel(writer, sheet_name=safe[:31], index=False)\n            st.download_button("Baixar Excel da carta", xlsx.getvalue(), file_name=f"carta_cpk_{datetime.now().strftime(\'%d_%m_%Y_%H%M\')}.xlsx", mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet", use_container_width=True)\n        with col_b:\n            pdf = make_pdf(st.session_state.carta_dados, results)\n            if pdf:\n                st.download_button("Baixar relatório PDF", pdf, file_name=f"relatorio_cpk_{datetime.now().strftime(\'%d_%m_%Y_%H%M\')}.pdf", mime="application/pdf", use_container_width=True)\n            else:\n                st.warning("Inclua reportlab no requirements.txt para exportar PDF.")\n',
    '__init__.py': '',
}


def ensure_runtime_files() -> None:
    """Cria a estrutura completa quando o GitHub/Streamlit Cloud não trouxer pastas ou módulos.

    Isso corrige o problema prático de deploy: pastas vazias são ignoradas pelo GitHub,
    e o app passa a recriar automaticamente diretórios, .gitkeep e arquivos de módulo ausentes.
    """
    for p in [
        MODULES_DIR,
        BASE_DIR / "data",
        BASE_DIR / "data" / "corporativo",
        BASE_DIR / "data" / "qualidade",
        BASE_DIR / "data" / "sqdcp",
        BASE_DIR / "data" / "cpk",
        BASE_DIR / "data" / "backups",
        BASE_DIR / "manual",
    ]:
        p.mkdir(parents=True, exist_ok=True)
        keep = p / ".gitkeep"
        if not keep.exists():
            keep.write_text("", encoding="utf-8")
    for filename, content in EMBEDDED_MODULES.items():
        target = MODULES_DIR / filename
        if not target.exists() or target.stat().st_size == 0:
            target.write_text(content, encoding="utf-8")
    if not MANUAL_FILE.exists():
        try:
            from reportlab.lib.pagesizes import A4
            from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
            from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle
            from reportlab.lib import colors
            from reportlab.lib.units import mm
            doc = SimpleDocTemplate(str(MANUAL_FILE), pagesize=A4, leftMargin=16*mm, rightMargin=16*mm, topMargin=14*mm, bottomMargin=14*mm)
            styles = getSampleStyleSheet()
            title = ParagraphStyle("TitleBI", parent=styles["Title"], fontSize=17, textColor=colors.HexColor("#0F5132"), spaceAfter=8)
            h = ParagraphStyle("HeadBI", parent=styles["Heading2"], fontSize=12, textColor=colors.HexColor("#0F5132"), spaceBefore=8, spaceAfter=4)
            body = ParagraphStyle("BodyBI", parent=styles["BodyText"], fontSize=9, leading=12)
            story = [Paragraph("Manual - BI Qualidade Corporativo", title)]
            story.append(Paragraph("Este aplicativo integra Indicadores de Qualidade, SQDCP/FMDS e Projeto CPK em uma unica tela inicial, com login, perfis de acesso, banco SQLite, auditoria e backup.", body))
            story.append(Paragraph("1. Acesso", h)); story.append(Paragraph("Use usuario e senha cadastrados. No primeiro acesso, entre com admin / QualidadeRS2026 e altere a senha na area Administracao.", body))
            story.append(Paragraph("2. Tela inicial", h)); story.append(Paragraph("A tela inicial apresenta cards para abrir cada modulo. O botao verde 'Tela inicial' fica visivel no topo de cada modulo para retorno rapido.", body))
            rows = [["Modulo", "Finalidade", "Persistencia"], ["Indicadores de Qualidade", "Analise de ocorrencias, motivos, atrasos, comparacao de periodos e exportacao.", "data/qualidade"], ["SQDCP/FMDS", "Gestao de indicadores, metas, serie historica, perdas por area, eficiencia e acoes.", "data/sqdcp"], ["Projeto CPK", "Cartas de inspecao, medicoes, Cp/Cpk, graficos, parecer e PDF/Excel.", "data/cpk"]]
            t = Table(rows, colWidths=[42*mm, 88*mm, 36*mm])
            t.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,0),colors.HexColor("#0F5132")),("TEXTCOLOR",(0,0),(-1,0),colors.white),("GRID",(0,0),(-1,-1),0.25,colors.grey),("VALIGN",(0,0),(-1,-1),"TOP"),("FONTSIZE",(0,0),(-1,-1),8)]))
            story.extend([Spacer(1,4*mm), t])
            story.append(Paragraph("3. Persistencia e backup", h)); story.append(Paragraph("Os dados sao salvos em pastas dedicadas e o banco corporativo fica em data/corporativo. Na area Administracao e possivel gerar backup ZIP com banco, dados, modulos e manual.", body))
            story.append(Paragraph("4. Boas praticas", h)); story.append(Paragraph("Sempre salve os registros antes de sair do modulo. Use o backup periodicamente antes de grandes alteracoes. No GitHub, mantenha a estrutura de pastas e arquivos .gitkeep versionados.", body))
            doc.build(story)
        except Exception:
            pass

